diffs.replacement:
{
  "name": "After The Fallen (2052)",
  "description": "A gritty, post-apocalyptic survival RPG set 22 years after a global nuclear collapse. Manage health, gear, and faction reputation in a world devoid of futuristic technology."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { GameState, TabView } from './types';
import { MainMenu } from './components/MainMenu';
import { Dock } from './components/Dock';
import { HealthView } from './components/views/HealthView';
import { BackpackView } from './components/views/BackpackView';
import { ArmoryView } from './components/views/ArmoryView';
import { StatsView } from './components/views/StatsView';
import { ReputationView } from './components/views/ReputationView';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [currentTab, setCurrentTab] = useState<TabView>(TabView.HEALTH);
  const [bootSequence, setBootSequence] = useState(false);

  useEffect(() => {
    // Simulate CRT warm-up effect on mount
    const timer = setTimeout(() => setBootSequence(true), 100);
    return () => clearTimeout(timer);
  }, []);

  const startGame = () => {
    setGameState(GameState.PLAYING);
  };

  const renderContent = () => {
    switch (currentTab) {
      case TabView.HEALTH:
        return <HealthView />;
      case TabView.BACKPACK:
        return <BackpackView />;
      case TabView.ARMORY:
        return <ArmoryView />;
      case TabView.STATS:
        return <StatsView />;
      case TabView.REPUTATION:
        return <ReputationView />;
      default:
        return <HealthView />;
    }
  };

  return (
    <div className={`relative min-h-screen w-full overflow-hidden bg-wasteland-black font-mono text-wasteland-paper transition-opacity duration-1000 ${bootSequence ? 'opacity-100' : 'opacity-0'}`}>

      {/* CRT Scanline Overlay */}
      <div className="crt-overlay fixed inset-0 z-50 h-full w-full opacity-30 pointer-events-none"></div>
      <div className="fixed inset-0 z-40 bg-gradient-to-b from-transparent to-black/40 pointer-events-none"></div>

      <div className="relative z-10 flex h-screen flex-col">
        {gameState === GameState.MENU ? (
          <MainMenu onStart={startGame} />
        ) : (
          <>
            {/* Top Status Bar (simplified for now) */}
            <header className="flex w-full items-center justify-between border-b-2 border-wasteland-dim bg-terminal-bg/90 p-4 shadow-lg backdrop-blur-sm">
              <div className="flex items-center gap-2">
                <div className="h-3 w-3 animate-pulse rounded-full bg-wasteland-green"></div>
                <span className="text-sm font-bold tracking-widest text-wasteland-green">PIP-OS v2.052</span>
              </div>
              <div className="text-xs text-stone-500">RAD: 0.4 mSv/h // DAY: 7892</div>
            </header>

            {/* Main Content Area */}
            <main className="flex-1 overflow-y-auto p-4 pb-32 sm:p-6 lg:p-8">
              <div className="mx-auto max-w-4xl animate-boot-up rounded-lg border border-wasteland-dim/30 bg-black/40 p-1 shadow-2xl backdrop-blur-md">
                {renderContent()}
              </div>
            </main>

            {/* Sticky Dock */}
            <Dock currentTab={currentTab} onTabChange={setCurrentTab} />
          </>
        )}
      </div>
    </div>
  );
};

export default App;

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
}

export enum TabView {
  HEALTH = 'HEALTH',
  BACKPACK = 'BACKPACK',
  ARMORY = 'ARMORY',
  STATS = 'STATS',
  REPUTATION = 'REPUTATION',
}

export interface Faction {
  id: string;
  name: string;
  description: string;
  reputation: number; // -100 to 100
  iconType: 'ISOTOPE' | 'OVERFELL';
}

export enum ItemRarity {
  COMMON = 'COMMON',
  WORN = 'WORN',
  RARE = 'RARE',
  PREWAR = 'PREWAR',
}

export interface Item {
  id: string;
  name: string;
  description: string;
  rarity: ItemRarity;
}

