import React from 'react';
import { TabView } from '../types';
import { IconHealth, IconBackpack, IconArmory, IconStats, IconReputation } from './icons/DockIcons';

interface DockProps {
  currentTab: TabView;
  onTabChange: (tab: TabView) => void;
}

export const Dock: React.FC<DockProps> = ({ currentTab, onTabChange }) => {
  const tabs = [
    { id: TabView.HEALTH, label: 'VITALS', icon: IconHealth },
    { id: TabView.BACKPACK, label: 'GEAR', icon: IconBackpack },
    { id: TabView.ARMORY, label: 'LOADOUT', icon: IconArmory },
    { id: TabView.STATS, label: 'DATA', icon: IconStats },
    { id: TabView.REPUTATION, label: 'COMMS', icon: IconReputation },
  ];

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 flex justify-center pb-4 pt-2">
      <div className="relative flex items-end gap-2 rounded-t-xl border-x-2 border-t-2 border-zinc-700 bg-zinc-900/95 p-2 px-4 shadow-[0_-5px_20px_rgba(0,0,0,0.8)] backdrop-blur-md">

        {/* Decorative Bolts */}
        <div className="absolute -left-1 top-2 h-2 w-2 rounded-full bg-zinc-600 shadow-inner"></div>
        <div className="absolute -right-1 top-2 h-2 w-2 rounded-full bg-zinc-600 shadow-inner"></div>

        {tabs.map((tab) => {
          const isActive = currentTab === tab.id;
          const Icon = tab.icon;

          return (
            <button
              key={tab.id}
              onClick={() => onTabChange(tab.id)}
              className={`group relative flex flex-col items-center justify-end rounded-lg p-2 transition-all duration-300 ease-out focus:outline-none ${
                isActive 
                  ? 'bg-zinc-800 text-wasteland-green -translate-y-2' 
                  : 'text-zinc-500 hover:bg-zinc-800/50 hover:text-wasteland-paper hover:-translate-y-1'
              }`}
            >
              {/* Active Indicator Light */}
              <div className={`absolute -top-1 h-1 w-6 rounded-full transition-all duration-300 ${isActive ? 'bg-wasteland-green shadow-[0_0_8px_rgba(74,222,128,0.8)]' : 'bg-transparent'}`} />

              <div className="relative z-10 p-1">
                <Icon className={`h-8 w-8 transition-transform duration-300 ${isActive ? 'scale-110' : 'group-hover:scale-105'}`} />
              </div>

              <span className={`mt-1 font-mono text-[10px] tracking-wider transition-all duration-200 ${isActive ? 'opacity-100 font-bold' : 'opacity-0 group-hover:opacity-100'}`}>
                {tab.label}
              </span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';

interface MainMenuProps {
