      <div className="absolute inset-0 z-0 bg-gradient-to-t from-black via-black/80 to-transparent"></div>

      <div className="z-10 flex flex-col items-center gap-8 text-center p-6">
        <div className="animate-flicker">
          <h1 className="font-display text-5xl sm:text-7xl lg:text-9xl tracking-tighter text-stone-300 drop-shadow-lg">
            AFTER THE <span className="text-red-900/80">FALLEN</span>
