{
  "name": "WARSAW: ZERO POINT",
  "description": "A text-based survival RPG set in the radioactive ruins of Warsaw. Feature LitRPG mechanics and MUD-style exploration.",
  "requestFramePermissions": []
}

export type StatKey = 'STR' | 'AGI' | 'INT' | 'END';

export interface PlayerStats {
  hp: number;
  maxHp: number;
  rads: number; // 0-1000
  hunger: number; // 0-100
  level: number;
  exp: number;
  nextLevelExp: number;
  attributes: Record<StatKey, number>;
}

export interface LogEntry {
  id: string;
  text: string;
  type: 'narrative' | 'combat' | 'system' | 'loot';
  timestamp: string;
}

export interface GameLocation {
  id: string;
  name: string;
  description: string;
  dangerLevel: number; // 1-5
  options: ActionOption[];
  visualType: 'RUINS' | 'TUNNEL' | 'RIVER' | 'SHELTER';
}

export interface ActionOption {
  id: string;
  label: string;
  actionType: 'MOVE' | 'SCAVENGE' | 'REST' | 'COMBAT';
  targetId?: string; // For movement
  reqStat?: StatKey;
  reqVal?: number;
}

export const INITIAL_STATS: PlayerStats = {
  hp: 100,
  maxHp: 100,
  rads: 50,
  hunger: 20,
  level: 1,
  exp: 0,
  nextLevelExp: 100,
  attributes: {
    STR: 5,
    AGI: 5,
    INT: 5,
    END: 5
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { PlayerStats, LogEntry, GameLocation, INITIAL_STATS, ActionOption } from './types';
import { TerminalLog } from './components/TerminalLog';
import { StatPanel } from './components/StatPanel';
import { VisualScope } from './components/VisualScope';
import { ActionGrid } from './components/ActionGrid';
import { LOCATIONS } from './data/world';

const App: React.FC = () => {
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS);
  const [currentLocId, setCurrentLocId] = useState<string>('start_bunker');
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [booted, setBooted] = useState(false);

  // Initial boot sequence
  useEffect(() => {
    const sequence = [
      "INIT_KERNEL... OK",
      "LOADING GEIGER_MODULE... OK",
      "CONNECTING TO SATELLITE... FAILED",
      "LOADING LOCAL CACHE: WARSAW_REGION_002",
      "SYSTEM READY."
    ];

    let delay = 0;
    sequence.forEach((msg, i) => {
      delay += 400 + Math.random() * 500;
      setTimeout(() => {
        addLog(msg, 'system');
        if (i === sequence.length - 1) setBooted(true);
      }, delay);
    });
  }, []);

  const addLog = (text: string, type: LogEntry['type'] = 'narrative') => {
    setLogs(prev => [...prev, {
      id: Math.random().toString(36).substr(2, 9),
      text,
      type,
      timestamp: new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' })
    }].slice(-50)); // Keep last 50 logs
  };

  const currentLocation = LOCATIONS[currentLocId] || LOCATIONS['start_bunker'];

  const handleAction = (action: ActionOption) => {
    // 1. Check Requirements
    if (action.reqStat && stats.attributes[action.reqStat] < (action.reqVal || 0)) {
      addLog(`[FAIL] ${action.reqStat} too low. Needed ${action.reqVal}.`, 'system');
      return;
    }

    // 2. Process Action
    switch (action.actionType) {
      case 'MOVE':
        if (action.targetId) {
          addLog(`Moving to ${action.label}...`, 'system');
          setCurrentLocId(action.targetId);
          // Small chance of event during travel could go here
          addLog(LOCATIONS[action.targetId!].description, 'narrative');
        }
        break;

      case 'SCAVENGE':
        addLog("Scanning area for resources...", 'system');
        const roll = Math.random() * 20 + stats.attributes.INT;
        if (roll > 15) {
          const xpGain = 15;
          addLog(`> FOUND: Scrap metal and filtered water. (+${xpGain} XP)`, 'loot');
          updateExp(xpGain);
        } else {
          addLog("> Nothing useful found. Just dust and echoes.", 'narrative');
        }
        break;

      case 'REST':
        addLog("Camp set. Vital signs normalizing.", 'system');
        setStats(prev => ({
          ...prev,
          hp: Math.min(prev.maxHp, prev.hp + 20),
          hunger: Math.min(100, prev.hunger + 10) // Hunger goes up when time passes, simplified here
        }));
        break;
    }
  };

  const updateExp = (amount: number) => {
    setStats(prev => {
      const newExp = prev.exp + amount;
      if (newExp >= prev.nextLevelExp) {
        addLog(`*** LEVEL UP: ${prev.level + 1} ***`, 'system');
        return {
          ...prev,
          level: prev.level + 1,
          exp: newExp - prev.nextLevelExp,
          nextLevelExp: Math.floor(prev.nextLevelExp * 1.5),
          maxHp: prev.maxHp + 10,
          hp: prev.maxHp + 10,
          attributes: {
            ...prev.attributes,
            STR: prev.attributes.STR + 1 // Simplified auto-level
          }
        };
      }
      return { ...prev, exp: newExp };
    });
  };

  if (!booted) {
    return (
      <div className="crt-container flex items-center justify-center bg-black text-term-amber">
        <div className="crt-overlay"></div>
        <div className="flex flex-col gap-2 font-mono text-xl">
           {logs.map(log => <div key={log.id}>{`> ${log.text}`}</div>)}
        </div>
      </div>
    );
  }

  return (
    <div className="crt-container flex flex-col bg-term-bg text-term-amber font-mono selection:bg-term-amber selection:text-black">
      <div className="crt-overlay"></div>
      <div className="crt-flicker"></div>

      {/* HEADER */}
      <header className="flex items-center justify-between border-b border-term-amber/30 bg-term-grid p-2 px-4 z-10">
        <div className="flex items-center gap-4">
            <span className="font-display text-2xl tracking-widest glow-text">WARSAW: ZERO POINT</span>
            <span className="text-xs text-term-amber-dim border border-term-amber-dim px-1">NET: OFFLINE</span>
        </div>
        <div className="text-xs text-term-amber-dim">
           LAT: 52.2297 N // LNG: 21.0122 E
        </div>
      </header>

      {/* MAIN CONTENT GRID */}
      <main className="flex-1 grid grid-cols-1 lg:grid-cols-12 overflow-hidden">

        {/* LEFT: TERMINAL LOG (MUD) */}
        <section className="lg:col-span-7 flex flex-col border-r border-term-amber/20 bg-black/80 p-4 overflow-hidden relative">
          <div className="absolute top-2 right-2 text-[10px] text-term-amber-dim">/VAR/LOG/SYS_MAIN</div>
          <TerminalLog logs={logs} />
        </section>

        {/* RIGHT: DASHBOARD (LitRPG) */}
        <section className="lg:col-span-5 flex flex-col bg-term-bg/90">

          {/* TOP RIGHT: VISUAL SCOPE */}
          <div className="h-1/3 border-b border-term-amber/20 p-4 relative flex items-center justify-center bg-scanlines">
             <div className="absolute top-2 left-2 text-[10px] text-term-amber-dim">VISUAL_FEED_INPUT</div>
             <VisualScope type={currentLocation.visualType} danger={currentLocation.dangerLevel} />
          </div>

          {/* MIDDLE RIGHT: STATS */}
          <div className="flex-1 p-4 overflow-y-auto">
             <StatPanel stats={stats} />
          </div>

          {/* BOTTOM RIGHT: ACTIONS */}
          <div className="p-4 border-t border-term-amber/20 bg-term-grid">
             <ActionGrid actions={currentLocation.options} onAction={handleAction} />
          </div>

        </section>
      </main>
    </div>
  );
};

