          </div>
        </div>
      ))}
      <div ref={endRef} />
    </div>
  );
};

const getTypeColor = (type: LogEntry['type']) => {
  switch (type) {
    case 'combat': return 'text-term-red font-bold';
    case 'system': return 'text-term-amber-dim italic';
    case 'loot': return 'text-white font-bold';
    default: return 'text-term-amber';
  }
};

