          </div>

          <h2 className="text-2xl font-display text-term-amber mb-4">{PATHS[selectedPath].name}</h2>
          <p className="text-sm font-mono text-white leading-relaxed mb-6 border-b border-term-gray pb-4">
            {PATHS[selectedPath].description}
