          <div className="space-y-4">
            <div>
              <div className="text-xs text-term-amber-dim mb-2">CUSTOM STAT SYSTEM</div>
              <div className="grid grid-cols-2 gap-2">
                {Object.entries(PATHS[selectedPath].baseStats).map(([label, val]) => (
                  <div key={label} className="flex justify-between items-center bg-term-grid px-2 py-1">
                    <span className="text-[10px] text-white">{label}</span>
                    <div className="flex gap-0.5">
                      {Array.from({length: 10}).map((_, i) => (
                        <div key={i} className={`w-1 h-2 ${i < val ? 'bg-term-amber' : 'bg-term-gray'}`} />
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div>
              <div className="text-xs text-term-amber-dim mb-1">TRAIT: {PATHS[selectedPath].startingTraits[0].name}</div>
              <p className="text-[10px] text-term-gray italic">"{PATHS[selectedPath].startingTraits[0].description}"</p>
            </div>

            {/* Sniper Specific Selection */}
            {selectedPath === 'THE_SNIPER' && (
              <div className="mt-4 border-t border-term-gray pt-4 animate-pulse-fast">
