        {/* Custom Stats & Traits */}
        <div className="flex flex-col gap-4">
           <div className="border border-term-amber/30 bg-term-grid p-4">
              <h3 className="text-lg font-display mb-4 border-b border-term-gray pb-2">
                 {PATHS[pathId].name.toUpperCase()} SYSTEM
              </h3>
              <div className="grid grid-cols-2 gap-4">
                {Object.entries(stats.attributes).map(([key, val]) => (
                  <div key={key} className="flex justify-between items-center">
                    <span className="text-term-amber-dim font-bold text-xs md:text-sm">{key}</span>
                    <span className="text-xl text-white font-mono">{val}</span>
