const StatusBar: React.FC<{label: string, val: number, max: number, color: string}> = ({label, val, max, color}) => (
  <div className="w-full">
    <div className="flex justify-between text-[10px] uppercase mb-1">
      <span>{label}</span>
      <span>{Math.round((val/max)*100)}%</span>
    </div>
    <div className="h-2 w-full bg-term-gray/50">
       <div style={{ width: `${(val/max)*100}%` }} className={`h-full ${color} shadow-[0_0_5px_currentColor]`}></div>
    </div>
  </div>
);

import React from 'react';
import { Item } from '../../types';

interface Props {
  items: string[];
}

export const InventoryView: React.FC<Props> = ({ items }) => {
  const slots = Array.from({ length: 20 });

  // Transform string array into display objects
  const displayItems = items.map((name, i) => ({
    id: i.toString(),
    name: name,
    rarity: name.includes('Enhanced') || name.includes('Machete') ? 'MIL-SPEC' : 'COMMON',
    type: 'JUNK'
  }));

  return (
    <div className="h-full flex flex-col p-1 pb-24">
      <div className="flex justify-between items-center mb-4 px-2 border-b border-term-amber/30 pb-2">
         <h2 className="text-xl font-display text-white">CARGO_HOLD</h2>
         <span className="text-xs font-mono text-term-amber-dim">CAPACITY: {items.length * 1.5}/40 KG</span>
      </div>

      <div className="grid grid-cols-4 gap-2 px-1">
        {slots.map((_, i) => {
          const item = displayItems[i];
          return (
            <div 
              key={i} 
              className={`
                aspect-square border border-term-gray bg-term-grid/50 relative group cursor-pointer
                hover:border-term-amber hover:bg-term-amber/10 transition-colors
              `}
            >
               <div className="absolute top-1 left-1 text-[8px] text-term-gray group-hover:text-term-amber font-mono">
                 {i < 9 ? `0${i+1}` : i+1}
               </div>

               {item && (
                 <div className="h-full w-full flex items-center justify-center p-2 text-center">
                    <span className={`text-[10px] font-bold ${item.rarity === 'MIL-SPEC' ? 'text-blue-400' : 'text-term-amber'}`}>
                      {item.name}
                    </span>
                 </div>
               )}
            </div>
          );
        })}
      </div>

      <div className="mt-auto border-t border-term-amber/20 pt-4 px-2">
         <div className="flex gap-2 mb-2">
            <button className="flex-1 bg-term-amber text-black font-bold text-xs py-2 hover:bg-white">EQUIP</button>
            <button className="flex-1 border border-term-red text-term-red font-bold text-xs py-2 hover:bg-term-red hover:text-black">DROP</button>
         </div>
         <p className="text-[10px] text-term-gray font-mono text-center">
            SELECT AN ITEM TO VIEW METADATA
         </p>
      </div>
    </div>
  );
};

