import React, { useState } from 'react';
import { PATHS } from '../../data/paths';
import { PathType } from '../../types';

interface Props {
  onComplete: (path: PathType, codename: string, nationality?: string) => void;
}

type Step = 'PATH' | 'DETAILS' | 'CODENAME';

export const CreationView: React.FC<Props> = ({ onComplete }) => {
  const [step, setStep] = useState<Step>('PATH');
  const [selectedPath, setSelectedPath] = useState<PathType>('THE_VOICE');
  const [nationality, setNationality] = useState<string>('USA'); // For Sniper
  const [selectedCodename, setSelectedCodename] = useState<string>('');

  const handlePathSelect = (path: PathType) => {
    setSelectedPath(path);
    // Reset selections when path changes
    setNationality('USA');
    setSelectedCodename(''); 
  };

  const handleConfirmPath = () => {
    setStep('CODENAME');
  };

  const handleFinalize = () => {
    onComplete(selectedPath, selectedCodename || PATHS[selectedPath].codenames[0], selectedPath === 'THE_SNIPER' ? nationality : undefined);
  };

  const pathList = Object.values(PATHS);

  return (
    <div className="h-full flex flex-col p-4 pb-24 overflow-y-auto">
      <h1 className="text-3xl font-display text-white mb-2 text-center">IDENTITY_INITIALIZATION</h1>

      {step === 'PATH' && (
        <>
          <p className="text-center text-xs text-term-amber-dim font-mono mb-8">SELECT NEURAL PATHWAY</p>
          <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Left Col: Selection List */}
            <div className="flex flex-col gap-2">
              {pathList.map((path) => (
                <button
                  key={path.id}
                  onClick={() => handlePathSelect(path.id)}
                  className={`
                    p-3 border text-left transition-all duration-300 relative overflow-hidden group
                    ${selectedPath === path.id 
                      ? 'border-term-amber bg-term-amber/10 text-white' 
                      : 'border-term-gray text-term-gray hover:border-term-amber-dim hover:text-term-amber'}
                  `}
                >
                  <div className="relative z-10 flex justify-between items-center">
                    <span className="font-display text-xl">{path.name.toUpperCase()}</span>
                    {selectedPath === path.id && <span className="animate-pulse text-xs">SELECTED</span>}
                  </div>
                  <div className={`absolute inset-0 bg-term-amber/5 transform transition-transform duration-500 origin-left ${selectedPath === path.id ? 'scale-x-100' : 'scale-x-0'}`}></div>
                </button>
              ))}
            </div>

            {/* Right Col: Details */}
            <div className="border border-term-amber bg-black p-4 flex flex-col relative">
              <div className="absolute top-0 right-0 p-1 bg-term-amber text-black text-[10px] font-bold">
                CLASS_DETAILS
              </div>

              <h2 className="text-2xl font-display text-term-amber mb-4">{PATHS[selectedPath].name}</h2>
              <p className="text-sm font-mono text-white leading-relaxed mb-6 border-b border-term-gray pb-4">
                {PATHS[selectedPath].description}
              </p>

              <div className="space-y-4">
                <div>
                  <div className="text-xs text-term-amber-dim mb-2">
                    ACRONYM STAT SYSTEM
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    {Object.entries(PATHS[selectedPath].baseStats).map(([label, val]) => (
                      <div key={label} className="flex justify-between items-center bg-term-grid px-2 py-1">
                        <span className="text-[10px] text-white">{label}</span>
                        <div className="flex gap-0.5">
                          {Array.from({length: 10}).map((_, i) => (
                            <div key={i} className={`w-1 h-2 ${i < val ? 'bg-term-amber' : 'bg-term-gray'}`} />
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>

                <div>
                  <div className="text-xs text-term-amber-dim mb-1">TRAIT: {PATHS[selectedPath].startingTraits[0].name}</div>
                  <p className="text-[10px] text-term-gray italic">"{PATHS[selectedPath].startingTraits[0].description}"</p>
                </div>

                {/* Sniper Specific Selection */}
                {selectedPath === 'THE_SNIPER' && (
                  <div className="mt-4 border-t border-term-gray pt-4 animate-pulse-fast">
                    <div className="text-xs text-term-red mb-2">SELECT ORIGIN FACTION</div>
                    <div className="flex gap-2">
                      {['USA', 'RUSSIA', 'CHINA'].map((nat) => (
                        <button
                          key={nat}
                          onClick={() => setNationality(nat)}
                          className={`flex-1 py-2 text-[10px] font-bold border ${nationality === nat ? 'bg-term-red text-black border-term-red' : 'border-term-gray text-term-gray'}`}
                        >
                          {nat}
                        </button>
                      ))}
                    </div>
                    <div className="mt-2 text-[10px] text-white">
                      Issue: {nationality === 'USA' ? 'M2010 Enhanced' : nationality === 'RUSSIA' ? 'SV-98M' : 'QBU-10 Anti-Mat'}
                    </div>
                  </div>
                )}
              </div>

              <button 
                onClick={handleConfirmPath}
                className="mt-auto pt-6 w-full group"
              >
                <div className="bg-term-amber text-black font-display text-xl py-3 text-center group-hover:bg-white transition-colors">
                  NEXT: CODENAME
                </div>
              </button>
            </div>
          </div>
        </>
      )}

      {step === 'CODENAME' && (
        <div className="flex-1 flex flex-col items-center max-w-2xl mx-auto w-full">
           <p className="text-center text-xs text-term-amber-dim font-mono mb-6">ESTABLISH RADIO HANDLE</p>

           <div className="w-full grid grid-cols-2 md:grid-cols-4 gap-3 mb-8">
              {PATHS[selectedPath].codenames.map((name) => (
                <button
                  key={name}
                  onClick={() => setSelectedCodename(name)}
                  className={`
                    p-2 text-center text-sm font-mono border transition-all
                    ${selectedCodename === name 
                      ? 'border-term-amber bg-term-amber text-black shadow-[0_0_15px_rgba(255,176,0,0.5)]' 
                      : 'border-term-gray text-term-gray hover:border-term-amber hover:text-term-amber'}
                  `}
                >
                  {name}
                </button>
              ))}
           </div>

           <div className="mt-auto w-full border border-term-amber/30 bg-term-grid p-6 text-center">
              <div className="text-xs text-term-gray mb-2">ASSIGNED IDENTITY</div>
              <div className="text-4xl font-display text-white mb-2">
                {selectedCodename || "SELECT_HANDLE"}
              </div>
              <div className="text-sm text-term-amber mb-6">{PATHS[selectedPath].name}</div>

              <button 
                onClick={handleFinalize}
                disabled={!selectedCodename}
                className={`
                  w-full py-3 font-display text-xl transition-colors
                  ${selectedCodename 
                    ? 'bg-term-amber text-black hover:bg-white' 
                    : 'bg-term-gray text-black cursor-not-allowed opacity-50'}
                `}
              >
                INITIALIZE LINK
              </button>

              <button 
                onClick={() => setStep('PATH')}
                className="mt-4 text-xs text-term-gray hover:text-white underline"
              >
                BACK TO PATH SELECTION
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { PlayerStats, GameLocation, INITIAL_STATS_TEMPLATE, TabView, PathType, Item } from './types';
import { PATHS } from './data/paths';
import { Dock } from './components/Dock';
import { StatusView } from './components/views/StatusView';
import { MapView } from './components/views/MapView';
import { InventoryView } from './components/views/InventoryView';
import { CommsView } from './components/views/CommsView';
import { CreationView } from './components/views/CreationView';
import { LOCATIONS } from './data/world';

type GameState = 'BOOT' | 'CREATION' | 'GAME';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('BOOT');
  const [currentTab, setCurrentTab] = useState<TabView>(TabView.STATUS);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS_TEMPLATE);
  const [playerPath, setPlayerPath] = useState<PathType | null>(null);
  const [playerCodename, setPlayerCodename] = useState<string>('');
  const [currentLocId, setCurrentLocId] = useState<string>('start_bunker');
  const [inventory, setInventory] = useState<string[]>([]); // Storing Item names for now

  // Initial boot sequence
  useEffect(() => {
    const timer = setTimeout(() => setGameState('CREATION'), 3000);
    return () => clearTimeout(timer);
  }, []);

  const handleCharacterCreated = (pathId: PathType, codename: string, nationality?: string) => {
    const pathConfig = PATHS[pathId];

    // Initialize stats based on Path
    const newStats: PlayerStats = {
      ...INITIAL_STATS_TEMPLATE,
      attributes: { ...pathConfig.baseStats },
      customMeters: []
    };

    // Add Path-specific meters
    if (pathId === 'THE_PSYCHO') {
      newStats.customMeters.push(
        { id: 'bloodlust', label: 'BLOODLUST', value: 0, max: 100, color: 'bg-term-red', decayRate: 1 },
        { id: 'psychosis', label: 'PSYCHOSIS', value: 10, max: 100, color: 'bg-purple-600' }
      );
    }
    if (pathId === 'THE_WANDERER') {
      newStats.customMeters.push(
        { id: 'stress', label: 'STRESS', value: 0, max: 100, color: 'bg-white' }
      );
    }

    // Add Starting Items
    let items = [...pathConfig.startingItems];
    if (pathId === 'THE_SNIPER' && nationality) {
      if (nationality === 'USA') items.push('M2010 Enhanced');
      if (nationality === 'RUSSIA') items.push('SV-98M');
      if (nationality === 'CHINA') items.push('QBU-10');
      items.push('Ballistic Drop Calculator');
    }

    setStats(newStats);
    setPlayerPath(pathId);
    setPlayerCodename(codename);
    setInventory(items);
    setGameState('GAME');
  };

  const handleTravel = (locId: string) => {
    setCurrentLocId(locId);
    setCurrentTab(TabView.STATUS); 
    // Logic for Wanderer Stress could go here
    if (playerPath === 'THE_WANDERER') {
       setStats(prev => ({
         ...prev,
         customMeters: prev.customMeters.map(m => m.id === 'stress' ? {...m, value: Math.max(0, m.value - 10)} : m)
       }));
    }
  };

  const renderContent = () => {
    const currentLocation = LOCATIONS[currentLocId] || LOCATIONS['start_bunker'];

    switch (currentTab) {
      case TabView.STATUS:
        return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
      case TabView.MAP:
        return <MapView currentLocationId={currentLocId} onTravel={handleTravel} />;
      case TabView.GEAR:
        return <InventoryView items={inventory} />;
      case TabView.COMMS:
        return <CommsView />;
      default:
        return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
    }
  };

  if (gameState === 'BOOT') {
    return (
      <div className="crt-container flex items-center justify-center bg-black text-term-amber h-screen w-screen">
        <div className="flex flex-col items-center gap-4 text-center px-4">
           <div className="font-display text-4xl animate-pulse tracking-widest text-term-red">WARSAW HAS FALLEN</div>
           <div className="w-64 h-2 bg-term-gray rounded-full overflow-hidden">
              <div className="h-full bg-term-amber animate-[width_2.5s_ease-in-out_forwards]" style={{width: '0%'}}></div>
           </div>
           <div className="font-mono text-xs text-term-amber-dim space-y-1">
              <p>LOADING KERNEL 2.0.52...</p>
              <p className="opacity-0 animate-[typewriter_0.1s_1s_forwards]">ACCESSING MEMORY BANKS: YEAR 2030...</p>
              <p className="opacity-0 animate-[typewriter_0.1s_2s_forwards]">ERROR: DATA CORRUPTED BY FALLOUT.</p>
           </div>
        </div>
      </div>
    );
  }

  if (gameState === 'CREATION') {
    return (
       <div className="crt-container flex flex-col h-screen w-full bg-term-bg text-term-amber font-mono overflow-hidden">
          <div className="crt-overlay"></div>
          <CreationView onComplete={handleCharacterCreated} />
       </div>
    );
  }

  return (
    <div className="crt-container flex flex-col h-screen w-full bg-term-bg text-term-amber font-mono selection:bg-term-amber selection:text-black overflow-hidden">
      <div className="crt-overlay"></div>
      <div className="crt-flicker"></div>

      {/* HEADER */}
      <header className="flex-none flex items-center justify-between border-b border-term-amber/30 bg-term-grid/90 p-3 z-10 backdrop-blur-md">
        <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-term-amber animate-pulse"></div>
            <span className="font-display text-xl tracking-widest glow-text">WHF-2052</span>
        </div>
        <div className="flex gap-2">
            <div className="text-[10px] text-term-amber-dim font-bold border border-term-amber-dim px-2 py-0.5 rounded">
              {playerCodename ? playerCodename.toUpperCase() : (playerPath ? PATHS[playerPath].name.toUpperCase() : 'UNKNOWN')}
            </div>
            <div className="text-[10px] text-term-amber-dim font-bold border border-term-amber-dim px-2 py-0.5 rounded hidden md:block">
              22 YEARS POST-EVENT
            </div>
        </div>
      </header>

      {/* MAIN CONTENT */}
      <main className="flex-1 relative overflow-hidden bg-[radial-gradient(circle_at_center,rgba(20,20,20,1)_0%,rgba(0,0,0,1)_100%)]">
         <div className="absolute inset-0 p-4 pb-20 overflow-y-auto scrollbar-thin scrollbar-thumb-term-amber scrollbar-track-term-gray">
            {renderContent()}
         </div>
      </main>

      {/* DOCK */}
      <Dock currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

export default App;

