import React, { useState } from 'react';
import { PATHS } from '../../data/paths';
import { PathType } from '../../types';
import { VoiceDetails } from '../creation/paths/VoiceDetails';
import { TraitorDetails } from '../creation/paths/TraitorDetails';
import { WandererDetails } from '../creation/paths/WandererDetails';
import { PsychoDetails } from '../creation/paths/PsychoDetails';
import { CannibalDetails } from '../creation/paths/CannibalDetails';
import { SniperDetails } from '../creation/paths/SniperDetails';

interface Props {
  onComplete: (path: PathType, codename: string, nationality?: string) => void;
}

type Step = 'PATH' | 'DETAILS' | 'CODENAME';

export const CreationView: React.FC<Props> = ({ onComplete }) => {
  const [step, setStep] = useState<Step>('PATH');
  const [selectedPath, setSelectedPath] = useState<PathType>('THE_VOICE');
  const [nationality, setNationality] = useState<string>('USA'); // For Sniper
  const [selectedCodename, setSelectedCodename] = useState<string>('');

  const handlePathSelect = (path: PathType) => {
    setSelectedPath(path);
    // Reset selections when path changes
    setNationality('USA');
    setSelectedCodename(''); 
  };

  const handleConfirmPath = () => {
    setStep('CODENAME');
  };

  const handleFinalize = () => {
    onComplete(selectedPath, selectedCodename || PATHS[selectedPath].codenames[0], selectedPath === 'THE_SNIPER' ? nationality : undefined);
  };

  const pathList = Object.values(PATHS);

  const renderDetails = () => {
    switch (selectedPath) {
      case 'THE_VOICE':
        return <VoiceDetails onNext={handleConfirmPath} />;
      case 'THE_TRAITOR':
        return <TraitorDetails onNext={handleConfirmPath} />;
      case 'THE_WANDERER':
        return <WandererDetails onNext={handleConfirmPath} />;
      case 'THE_PSYCHO':
        return <PsychoDetails onNext={handleConfirmPath} />;
      case 'THE_CANNIBAL':
        return <CannibalDetails onNext={handleConfirmPath} />;
      case 'THE_SNIPER':
        return <SniperDetails onNext={handleConfirmPath} nationality={nationality} setNationality={setNationality} />;
      default:
        return <VoiceDetails onNext={handleConfirmPath} />;
    }
  };

  return (
    <div className="h-full flex flex-col p-4 pb-24 overflow-y-auto">
      <h1 className="text-3xl font-display text-white mb-2 text-center">IDENTITY_INITIALIZATION</h1>

      {step === 'PATH' && (
        <>
          <p className="text-center text-xs text-term-amber-dim font-mono mb-8">SELECT NEURAL PATHWAY</p>
          <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Left Col: Selection List */}
            <div className="flex flex-col gap-2">
              {pathList.map((path) => (
                <button
                  key={path.id}
                  onClick={() => handlePathSelect(path.id)}
                  className={`
                    p-3 border text-left transition-all duration-300 relative overflow-hidden group
                    ${selectedPath === path.id 
                      ? 'border-term-amber bg-term-amber/10 text-white' 
                      : 'border-term-gray text-term-gray hover:border-term-amber-dim hover:text-term-amber'}
                  `}
                >
                  <div className="relative z-10 flex justify-between items-center">
                    <span className="font-display text-xl">{path.name.toUpperCase()}</span>
                    {selectedPath === path.id && <span className="animate-pulse text-xs">SELECTED</span>}
                  </div>
                  <div className={`absolute inset-0 bg-term-amber/5 transform transition-transform duration-500 origin-left ${selectedPath === path.id ? 'scale-x-100' : 'scale-x-0'}`}></div>
                </button>
              ))}
            </div>

            {/* Right Col: Details (Separated Components) */}
            <div className="relative">
              {renderDetails()}
            </div>
          </div>
        </>
      )}

      {step === 'CODENAME' && (
        <div className="flex-1 flex flex-col items-center max-w-2xl mx-auto w-full">
           <p className="text-center text-xs text-term-amber-dim font-mono mb-6">ESTABLISH RADIO HANDLE</p>

           <div className="w-full grid grid-cols-2 md:grid-cols-4 gap-3 mb-8">
              {PATHS[selectedPath].codenames.map((name) => (
                <button
                  key={name}
                  onClick={() => setSelectedCodename(name)}
                  className={`
                    p-2 text-center text-sm font-mono border transition-all
                    ${selectedCodename === name 
                      ? 'border-term-amber bg-term-amber text-black shadow-[0_0_15px_rgba(255,176,0,0.5)]' 
                      : 'border-term-gray text-term-gray hover:border-term-amber hover:text-term-amber'}
                  `}
                >
                  {name}
                </button>
              ))}
           </div>

           <div className="mt-auto w-full border border-term-amber/30 bg-term-grid p-6 text-center">
              <div className="text-xs text-term-gray mb-2">ASSIGNED IDENTITY</div>
              <div className="text-4xl font-display text-white mb-2">
                {selectedCodename || "SELECT_HANDLE"}
              </div>
              <div className="text-sm text-term-amber mb-6">{PATHS[selectedPath].name}</div>

              <button 
                onClick={handleFinalize}
                disabled={!selectedCodename}
                className={`
                  w-full py-3 font-display text-xl transition-colors
                  ${selectedCodename 
                    ? 'bg-term-amber text-black hover:bg-white' 
                    : 'bg-term-gray text-black cursor-not-allowed opacity-50'}
                `}
              >
                INITIALIZE LINK
              </button>

              <button 
                onClick={() => setStep('PATH')}
                className="mt-4 text-xs text-term-gray hover:text-white underline"
              >
                BACK TO PATH SELECTION
              </button>
           </div>
        </div>
      )}
    </div>
  );
};

export enum TabView {
  STATUS = 'STATUS',
  MAP = 'MAP',
  GEAR = 'GEAR',
  COMMS = 'COMMS',
}

export type PathType = 'THE_VOICE' | 'THE_TRAITOR' | 'THE_WANDERER' | 'THE_PSYCHO' | 'THE_CANNIBAL' | 'THE_SNIPER';

export interface Trait {
  id: string;
  name: string;
  description: string;
  effect: string; // Description of gameplay effect
}

export interface Meter {
  id: string;
  label: string;
  value: number;
  max: number;
  color: string;
  decayRate?: number; // Per tick
}

export interface PlayerStats {
  hp: number;
  maxHp: number;
  rads: number;
  hunger: number;
  level: number;
  exp: number;
  nextLevelExp: number;
  // Stats are now dynamic keys based on Path
  attributes: Record<string, number>;
  // Meters specific to the class (e.g. Psychosis, Stress, Bloodlust)
  customMeters: Meter[];
}

export interface PathConfig {
  id: PathType;
  name: string;
  description: string;
  // Attributes now support variable length for Acronyms (e.g. W.H.I.S.P.E.R)
  attributeLabels: string[]; 
  baseStats: Record<string, number>;
  startingTraits: Trait[];
  startingItems: string[]; // IDs of items
  codenames: string[]; // List of potential names
  carryCapacity: number; // Base capacity in KG
}

export interface GameLocation {
  id: string;
  name: string;
  description: string;
  dangerLevel: number; // 1-5
  coordinates: { x: number; y: number };
  isUnlocked: boolean;
}

export interface Item {
  id: string;
  name: string;
  type: 'WEAPON' | 'ARMOR' | 'CONSUMABLE' | 'JUNK' | 'GADGET';
  rarity: 'COMMON' | 'MIL-SPEC' | 'PROTOTYPE' | 'LEGENDARY';
  description: string;
  weight: number; // in KG
}

