import React, { useState, useEffect } from 'react';
import { PlayerStats, GameLocation, INITIAL_STATS_TEMPLATE, TabView, PathType, Item } from './types';
import { PATHS } from './data/paths';
import { Dock } from './components/Dock';
import { StatusView } from './components/views/StatusView';
import { MapView } from './components/views/MapView';
import { InventoryView } from './components/views/InventoryView';
import { CommsView } from './components/views/CommsView';
import { CreationView } from './components/views/CreationView';
import { LOCATIONS } from './data/world';

type GameState = 'BOOT' | 'CREATION' | 'GAME';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('BOOT');
  const [currentTab, setCurrentTab] = useState<TabView>(TabView.STATUS);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS_TEMPLATE);
  const [playerPath, setPlayerPath] = useState<PathType | null>(null);
  const [playerCodename, setPlayerCodename] = useState<string>('');
  const [currentLocId, setCurrentLocId] = useState<string>('start_bunker');
  const [inventory, setInventory] = useState<string[]>([]); // Storing Item names for now

  // Initial boot sequence
  useEffect(() => {
    const timer = setTimeout(() => setGameState('CREATION'), 3000);
    return () => clearTimeout(timer);
  }, []);

  const handleCharacterCreated = (pathId: PathType, codename: string, nationality?: string) => {
    const pathConfig = PATHS[pathId];

    // Initialize stats based on Path
    const newStats: PlayerStats = {
      ...INITIAL_STATS_TEMPLATE,
      attributes: { ...pathConfig.baseStats },
      customMeters: []
    };

    // Add Path-specific meters
    if (pathId === 'THE_PSYCHO') {
      newStats.customMeters.push(
        { id: 'bloodlust', label: 'BLOODLUST', value: 0, max: 100, color: 'bg-term-red', decayRate: 1 },
        { id: 'psychosis', label: 'PSYCHOSIS', value: 10, max: 100, color: 'bg-purple-600' }
      );
    }
    if (pathId === 'THE_WANDERER') {
      newStats.customMeters.push(
        { id: 'stress', label: 'STRESS', value: 0, max: 100, color: 'bg-white' }
      );
    }

    // Add Starting Items
    let items = [...pathConfig.startingItems];
    if (pathId === 'THE_SNIPER' && nationality) {
      if (nationality === 'USA') items.push('M2010 Enhanced');
      if (nationality === 'RUSSIA') items.push('SV-98M');
      if (nationality === 'CHINA') items.push('QBU-10');
      items.push('Ballistic Drop Calculator');
    }

    setStats(newStats);
    setPlayerPath(pathId);
    setPlayerCodename(codename);
    setInventory(items);
    setGameState('GAME');
  };

  const handleTravel = (locId: string) => {
    setCurrentLocId(locId);
    setCurrentTab(TabView.STATUS); 
    // Logic for Wanderer Stress could go here
    if (playerPath === 'THE_WANDERER') {
       setStats(prev => ({
         ...prev,
         customMeters: prev.customMeters.map(m => m.id === 'stress' ? {...m, value: Math.max(0, m.value - 10)} : m)
       }));
    }
  };

  const renderContent = () => {
    const currentLocation = LOCATIONS[currentLocId] || LOCATIONS['start_bunker'];

    switch (currentTab) {
      case TabView.STATUS:
        return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
      case TabView.MAP:
        return <MapView currentLocationId={currentLocId} onTravel={handleTravel} />;
      case TabView.GEAR:
        return <InventoryView items={inventory} pathId={playerPath!} />;
      case TabView.COMMS:
        return <CommsView />;
      default:
        return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
    }
  };

  if (gameState === 'BOOT') {
    return (
      <div className="crt-container flex items-center justify-center bg-black text-term-amber h-screen w-screen">
        <div className="flex flex-col items-center gap-4 text-center px-4">
           <div className="font-display text-4xl animate-pulse tracking-widest text-term-red">WARSAW HAS FALLEN</div>
           <div className="w-64 h-2 bg-term-gray rounded-full overflow-hidden">
              <div className="h-full bg-term-amber animate-[width_2.5s_ease-in-out_forwards]" style={{width: '0%'}}></div>
           </div>
           <div className="font-mono text-xs text-term-amber-dim space-y-1">
              <p>LOADING KERNEL 2.0.52...</p>
              <p className="opacity-0 animate-[typewriter_0.1s_1s_forwards]">ACCESSING MEMORY BANKS: YEAR 2030...</p>
              <p className="opacity-0 animate-[typewriter_0.1s_2s_forwards]">ERROR: DATA CORRUPTED BY FALLOUT.</p>
           </div>
        </div>
      </div>
    );
  }

  if (gameState === 'CREATION') {
    return (
       <div className="crt-container flex flex-col h-screen w-full bg-term-bg text-term-amber font-mono overflow-hidden">
          <div className="crt-overlay"></div>
          <CreationView onComplete={handleCharacterCreated} />
       </div>
    );
  }

  return (
    <div className="crt-container flex flex-col h-screen w-full bg-term-bg text-term-amber font-mono selection:bg-term-amber selection:text-black overflow-hidden">
      <div className="crt-overlay"></div>
      <div className="crt-flicker"></div>

      {/* HEADER */}
      <header className="flex-none flex items-center justify-between border-b border-term-amber/30 bg-term-grid/90 p-3 z-10 backdrop-blur-md">
        <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-term-amber animate-pulse"></div>
            <span className="font-display text-xl tracking-widest glow-text">WHF-2052</span>
        </div>
        <div className="flex gap-2">
            <div className="text-[10px] text-term-amber-dim font-bold border border-term-amber-dim px-2 py-0.5 rounded">
              {playerCodename ? playerCodename.toUpperCase() : (playerPath ? PATHS[playerPath].name.toUpperCase() : 'UNKNOWN')}
            </div>
            <div className="text-[10px] text-term-amber-dim font-bold border border-term-amber-dim px-2 py-0.5 rounded hidden md:block">
              22 YEARS POST-EVENT
            </div>
        </div>
      </header>

      {/* MAIN CONTENT */}
      <main className="flex-1 relative overflow-hidden bg-[radial-gradient(circle_at_center,rgba(20,20,20,1)_0%,rgba(0,0,0,1)_100%)]">
         <div className="absolute inset-0 p-4 pb-20 overflow-y-auto scrollbar-thin scrollbar-thumb-term-amber scrollbar-track-term-gray">
            {renderContent()}
         </div>
      </main>

      {/* DOCK */}
      <Dock currentTab={currentTab} onTabChange={setCurrentTab} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Item, PathType } from '../../types';
import { PATHS } from '../../data/paths';
import { getItem } from '../../data/items';

interface Props {
  items: string[];
  pathId: PathType;
}

type WeightUnit = 'KG' | 'LB';

export const InventoryView: React.FC<Props> = ({ items, pathId }) => {
  const [selectedItemIndex, setSelectedItemIndex] = useState<number | null>(null);
  const [weightUnit, setWeightUnit] = useState<WeightUnit>('KG');

  // Convert string list to detailed objects
  const inventoryItems = items.map((name, index) => ({
    ...getItem(name),
    uniqueId: `${index}_${name}` // Add unique ID for React keys if duplicate items exist
  }));

  const maxWeightKg = PATHS[pathId].carryCapacity;
  const currentWeightKg = inventoryItems.reduce((acc, item) => acc + item.weight, 0);

  // Conversion Helpers
  const displayWeight = (kg: number) => {
    if (weightUnit === 'KG') return kg.toFixed(1);
    return (kg * 2.20462).toFixed(1);
  };

  const getPercentage = () => Math.min(100, (currentWeightKg / maxWeightKg) * 100);

  const selectedItem = selectedItemIndex !== null ? inventoryItems[selectedItemIndex] : null;

  return (
    <div className="h-full flex flex-col p-1 pb-24 relative">
      {/* Header & Capacity */}
      <div className="flex flex-col gap-2 mb-4 px-2 border-b border-term-amber/30 pb-4">
         <div className="flex justify-between items-center">
            <h2 className="text-xl font-display text-white">CARGO_HOLD</h2>
            <button 
              onClick={() => setWeightUnit(prev => prev === 'KG' ? 'LB' : 'KG')}
              className="text-[10px] font-bold border border-term-amber px-2 py-1 text-term-amber hover:bg-term-amber hover:text-black transition-colors"
            >
              UNIT: {weightUnit}
            </button>
         </div>

         {/* Weight Bar */}
         <div className="w-full">
            <div className="flex justify-between text-[10px] text-term-gray font-mono mb-1">
               <span>LOAD: {displayWeight(currentWeightKg)} {weightUnit}</span>
               <span>MAX: {displayWeight(maxWeightKg)} {weightUnit}</span>
            </div>
            <div className="h-2 bg-term-grid border border-term-gray w-full relative">
               <div 
                 className={`h-full transition-all duration-500 ${getPercentage() > 90 ? 'bg-term-red animate-pulse' : 'bg-term-amber'}`} 
                 style={{ width: `${getPercentage()}%` }}
               ></div>
               {/* Tick marks */}
               <div className="absolute inset-0 flex justify-between px-1">
                 {[...Array(10)].map((_, i) => <div key={i} className="w-[1px] h-full bg-black/50"></div>)}
               </div>
            </div>
         </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-4 md:grid-cols-5 gap-2 px-1 flex-1 content-start overflow-y-auto min-h-0">
        {Array.from({ length: 20 }).map((_, i) => {
          const item = inventoryItems[i];
          const isSelected = selectedItemIndex === i;

          return (
            <div 
              key={i} 
              onClick={() => item && setSelectedItemIndex(i)}
              className={`
                aspect-square border relative group cursor-pointer transition-all duration-200
                ${isSelected 
                  ? 'border-term-amber bg-term-amber/20 shadow-[0_0_10px_rgba(255,176,0,0.3)]' 
                  : 'border-term-gray bg-term-grid/50 hover:border-term-amber-dim hover:bg-term-amber/5'}
              `}
            >
               <div className="absolute top-1 left-1 text-[8px] text-term-gray group-hover:text-term-amber font-mono">
                 {i < 9 ? `0${i+1}` : i+1}
               </div>

               {item ? (
                 <div className="h-full w-full flex flex-col items-center justify-center p-1 text-center">
                    {/* Rarity Indicator */}
                    <div className={`w-1 h-1 rounded-full mb-1 ${
                      item.rarity === 'LEGENDARY' ? 'bg-purple-500 shadow-[0_0_5px_purple]' :
                      item.rarity === 'PROTOTYPE' ? 'bg-cyan-400 shadow-[0_0_5px_cyan]' :
                      item.rarity === 'MIL-SPEC' ? 'bg-blue-500' : 
                      'bg-term-gray'
                    }`}></div>

                    <span className={`text-[9px] leading-tight font-bold ${
                      item.rarity === 'LEGENDARY' ? 'text-purple-300' :
                      item.rarity === 'PROTOTYPE' ? 'text-cyan-200' :
                      item.rarity === 'MIL-SPEC' ? 'text-blue-300' : 
                      'text-term-amber'
                    }`}>
                      {item.name}
                    </span>
                 </div>
               ) : (
                 <div className="h-full w-full flex items-center justify-center opacity-10">
                    <div className="w-2 h-2 border border-term-gray"></div>
                 </div>
               )}
            </div>
          );
        })}
      </div>

      {/* Detail Panel Popup (Bottom) */}
      <div className={`
        absolute bottom-20 left-1 right-1 border border-term-amber bg-black/95 p-4 z-20 backdrop-blur-md transform transition-transform duration-300
        ${selectedItem ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0 pointer-events-none'}
      `}>
         {selectedItem && (
           <>
             <div className="flex justify-between items-start mb-2">
                <div>
                   <h3 className={`font-display text-lg ${
                      selectedItem.rarity === 'LEGENDARY' ? 'text-purple-400' :
                      selectedItem.rarity === 'PROTOTYPE' ? 'text-cyan-400' :
                      selectedItem.rarity === 'MIL-SPEC' ? 'text-blue-400' : 
                      'text-term-amber'
                   }`}>
                     {selectedItem.name}
                   </h3>
                   <div className="text-[10px] text-term-gray font-mono uppercase">
                      {selectedItem.type} // {selectedItem.rarity}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-xl font-display text-white">{displayWeight(selectedItem.weight)} <span className="text-xs text-term-gray">{weightUnit}</span></div>
                   <button onClick={() => setSelectedItemIndex(null)} className="text-[10px] text-term-red hover:underline">CLOSE</button>
                </div>
             </div>

             <div className="text-xs text-stone-300 font-mono mb-4 border-l-2 border-term-gray pl-2">
                "{selectedItem.description}"
             </div>

             <div className="flex gap-2">
                <button className="flex-1 bg-term-amber text-black font-bold text-xs py-2 hover:bg-white transition-colors">EQUIP</button>
                <button className="flex-1 border border-term-red text-term-red font-bold text-xs py-2 hover:bg-term-red hover:text-black transition-colors">DROP</button>
             </div>
           </>
         )}
      </div>

      {!selectedItem && (
        <div className="mt-auto pt-2 px-2 pb-2 text-[10px] text-term-gray font-mono text-center animate-pulse">
            SELECT AN ITEM TO ACCESS METADATA
        </div>
      )}
    </div>
  );
};

export enum TabView {
  STATUS = 'STATUS',
  MAP = 'MAP',
  GEAR = 'GEAR',
  COMMS = 'COMMS',
  REPUTATION = 'REPUTATION',
  RELATIONS = 'RELATIONS',
  ARCHIVES = 'ARCHIVES',
  FABRICATION = 'FABRICATION',
}

export type PathType = 'THE_VOICE' | 'THE_TRAITOR' | 'THE_WANDERER' | 'THE_PSYCHO' | 'THE_CANNIBAL' | 'THE_SNIPER';

export interface Trait {
  id: string;
  name: string;
  description: string;
  effect: string; // Description of gameplay effect
}

export interface Meter {
  id: string;
  label: string;
  value: number;
  max: number;
  color: string;
  decayRate?: number; // Per tick
}

export interface PlayerStats {
  hp: number;
  maxHp: number;
  rads: number;
  hunger: number;
  level: number;
  exp: number;
  nextLevelExp: number;
  // Stats are now dynamic keys based on Path
  attributes: Record<string, number>;
  // Meters specific to the class (e.g. Psychosis, Stress, Bloodlust)
  customMeters: Meter[];
}

export interface PathConfig {
  id: PathType;
  name: string;
  description: string;
  // Attributes now support variable length for Acronyms (e.g. W.H.I.S.P.E.R)
  attributeLabels: string[]; 
  baseStats: Record<string, number>;
  startingTraits: Trait[];
  startingItems: string[]; // IDs of items
  codenames: string[]; // List of potential names
  carryCapacity: number; // Base capacity in KG
}

export interface GameLocation {
  id: string;
  name: string;
  description: string;
  dangerLevel: number; // 1-5
  coordinates: { x: number; y: number };
  isUnlocked: boolean;
}

export interface Item {
  id: string;
  name: string;
  type: 'WEAPON' | 'ARMOR' | 'CONSUMABLE' | 'JUNK' | 'GADGET';
  rarity: 'COMMON' | 'MIL-SPEC' | 'PROTOTYPE' | 'LEGENDARY';
  description: string;
  weight: number; // in KG
}

export const INITIAL_STATS_TEMPLATE: PlayerStats = {
  hp: 100,
  maxHp: 100,
  rads: 0,
  hunger: 0,
  level: 1,
  exp: 0,
  nextLevelExp: 1000,
  attributes: {},
  customMeters: []
};

// Social Interfaces
export interface Faction {
  id: string;
  name: string;
  description: string;
  reputation: number; // -1000 to 1000
}

export interface NPC {
  id: string;
  name: string;
  role: string;
  affection: number; // 0 to 100 (Hearts)
  stage: number; // Relationship Stage
  dialogueState: string;
  isUnlocked: boolean;
}

