import React, { useState, useEffect } from 'react';
import { PlayerStats, GameLocation, INITIAL_STATS_TEMPLATE, TabView, PathType, Item } from './types';
import { PATHS } from './data/paths';
import { Dock } from './components/Dock';
import { StatusView } from './components/views/StatusView';
import { MapView } from './components/views/MapView';
import { InventoryView } from './components/views/InventoryView';
import { CommsView } from './components/views/CommsView';
import { CreationView } from './components/views/CreationView';
import { ReputationView } from './components/views/ReputationView';
import { RelationshipsView } from './components/views/RelationshipsView';
import { ArchivesView } from './components/views/ArchivesView';
import { FabricationView } from './components/views/FabricationView';
import { LOCATIONS } from './data/world';

type GameState = 'BOOT' | 'CREATION' | 'GAME';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('BOOT');
  const [currentTab, setCurrentTab] = useState<TabView>(TabView.STATUS);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS_TEMPLATE);
  const [playerPath, setPlayerPath] = useState<PathType | null>(null);
  const [playerCodename, setPlayerCodename] = useState<string>('');
  const [currentLocId, setCurrentLocId] = useState<string>('start_bunker');
  const [inventory, setInventory] = useState<string[]>([]); // Storing Item names for now

  // Initial boot sequence
  useEffect(() => {
    const timer = setTimeout(() => setGameState('CREATION'), 3000);
    return () => clearTimeout(timer);
  }, []);

  const handleCharacterCreated = (pathId: PathType, codename: string, nationality?: string) => {
    const pathConfig = PATHS[pathId];

    // Initialize stats based on Path
    const newStats: PlayerStats = {
      ...INITIAL_STATS_TEMPLATE,
      attributes: { ...pathConfig.baseStats },
      customMeters: []
    };

    // Add Path-specific meters
    if (pathId === 'THE_PSYCHO') {
      newStats.customMeters.push(
        { id: 'bloodlust', label: 'BLOODLUST', value: 0, max: 100, color: 'bg-term-red', decayRate: 1 },
        { id: 'psychosis', label: 'PSYCHOSIS', value: 10, max: 100, color: 'bg-purple-600' }
      );
    }
    if (pathId === 'THE_WANDERER') {
      newStats.customMeters.push(
        { id: 'stress', label: 'STRESS', value: 0, max: 100, color: 'bg-white' }
      );
    }

    // Add Starting Items
    let items = [...pathConfig.startingItems];
    if (pathId === 'THE_SNIPER' && nationality) {
      if (nationality === 'USA') items.push('M2010 Enhanced');
      if (nationality === 'RUSSIA') items.push('SV-98M');
      if (nationality === 'CHINA') items.push('QBU-10');
      items.push('Ballistic Drop Calculator');
    }

    setStats(newStats);
    setPlayerPath(pathId);
    setPlayerCodename(codename);
    setInventory(items);
    setGameState('GAME');
  };

  const handleTravel = (locId: string) => {
    setCurrentLocId(locId);
    setCurrentTab(TabView.STATUS); 
    // Logic for Wanderer Stress could go here
    if (playerPath === 'THE_WANDERER') {
       setStats(prev => ({
         ...prev,
         customMeters: prev.customMeters.map(m => m.id === 'stress' ? {...m, value: Math.max(0, m.value - 10)} : m)
       }));
    }
  };

  const renderContent = () => {
    const currentLocation = LOCATIONS[currentLocId] || LOCATIONS['start_bunker'];

    switch (currentTab) {
      case TabView.STATUS:
        return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
      case TabView.MAP:
        return <MapView currentLocationId={currentLocId} onTravel={handleTravel} />;
      case TabView.GEAR:
        return <InventoryView items={inventory} pathId={playerPath!} />;
      case TabView.COMMS:
        return <CommsView />;
      case TabView.REPUTATION:
        return <ReputationView />;
      case TabView.RELATIONS:
        return <RelationshipsView />;
      case TabView.ARCHIVES:
        return <ArchivesView />;
      case TabView.FABRICATION:
        return <FabricationView />;
      default:
        return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
    }
  };

  if (gameState === 'BOOT') {
    return (
      <div className="flex items-center justify-center h-screen w-screen bg-[#080808] font-mono">
        <div className="crt-container w-full max-w-[400px] h-[700px] flex items-center justify-center bg-black text-term-amber border border-term-gray rounded-xl shadow-2xl relative overflow-hidden">
          <div className="crt-overlay"></div>
          <div className="crt-flicker"></div>
          <div className="flex flex-col items-center gap-4 text-center px-4 z-10">
             <div className="font-display text-4xl animate-pulse tracking-widest text-term-red">WARSAW HAS FALLEN</div>
             <div className="w-64 h-2 bg-term-gray rounded-full overflow-hidden">
                <div className="h-full bg-term-amber animate-[width_2.5s_ease-in-out_forwards]" style={{width: '0%'}}></div>
             </div>
             <div className="font-mono text-xs text-term-amber-dim space-y-1">
                <p>LOADING KERNEL 2.0.52...</p>
                <p className="opacity-0 animate-[typewriter_0.1s_1s_forwards]">ACCESSING MEMORY BANKS: YEAR 2030...</p>
                <p className="opacity-0 animate-[typewriter_0.1s_2s_forwards]">ERROR: DATA CORRUPTED BY FALLOUT.</p>
             </div>
          </div>
        </div>
      </div>
    );
  }

  // Wrapper Style for Device Look
  return (
    <div className="flex items-center justify-center h-screen w-screen bg-[#080808] p-4 font-mono">
      <div className="crt-container relative w-full max-w-[420px] h-full max-h-[850px] flex flex-col bg-term-bg text-term-amber shadow-[0_0_50px_rgba(0,0,0,0.8)] border-2 border-[#222] rounded-lg overflow-hidden ring-1 ring-white/10">
        <div className="crt-overlay"></div>
        <div className="crt-flicker"></div>

        {/* HEADER */}
        <header className="flex-none flex items-center justify-between border-b border-term-amber/30 bg-term-grid/90 p-4 z-20 backdrop-blur-md">
          <div className="flex items-center gap-3">
              <div className="w-2 h-2 rounded-full bg-term-amber animate-pulse"></div>
              <span className="font-display text-xl tracking-widest glow-text">WHF-2052</span>
          </div>
          <div className="flex gap-2">
              <div className="text-[10px] text-term-amber-dim font-bold border border-term-amber-dim px-2 py-0.5 rounded">
                {playerCodename ? playerCodename.toUpperCase() : (playerPath ? PATHS[playerPath].name.toUpperCase() : 'UNKNOWN')}
              </div>
          </div>
        </header>

        {/* MAIN CONTENT */}
        <main className="flex-1 relative overflow-hidden bg-[radial-gradient(circle_at_center,rgba(20,20,20,1)_0%,rgba(0,0,0,1)_100%)] z-10">
           {/* Passing onComplete only if in creation mode, but we switch rendering inside handleCharacterCreated */}
           {gameState === 'CREATION' ? (
              <CreationView onComplete={handleCharacterCreated} />
           ) : (
              <div className="absolute inset-0 pb-20 overflow-y-auto scrollbar-thin scrollbar-thumb-term-amber scrollbar-track-term-gray">
                  {renderContent()}
              </div>
           )}
        </main>

        {/* DOCK - Only show in GAME state */}
        {gameState === 'GAME' && <Dock currentTab={currentTab} onTabChange={setCurrentTab} />}
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { TabView } from '../types';
import { 
  IconStatus, IconMap, IconGear, IconComms, 
  IconReputation, IconRelations, IconArchives, IconFabrication 
} from './icons/DockIcons';

interface DockProps {
  currentTab: TabView;
  onTabChange: (tab: TabView) => void;
}

export const Dock: React.FC<DockProps> = ({ currentTab, onTabChange }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  const tabs = [
    { id: TabView.STATUS, label: 'BIO_SIG', icon: IconStatus },
    { id: TabView.MAP, label: 'NAV_SAT', icon: IconMap },
    { id: TabView.GEAR, label: 'LOADOUT', icon: IconGear },
    { id: TabView.FABRICATION, label: 'FAB', icon: IconFabrication },
    { id: TabView.REPUTATION, label: 'REP', icon: IconReputation },
    { id: TabView.RELATIONS, label: 'BOND', icon: IconRelations },
    { id: TabView.ARCHIVES, label: 'DATA', icon: IconArchives },
    { id: TabView.COMMS, label: 'NET_LOG', icon: IconComms },
  ];

  // Auto scroll to active element
  useEffect(() => {
    if (scrollRef.current) {
      const activeBtn = scrollRef.current.querySelector('[data-active="true"]');
      if (activeBtn) {
        activeBtn.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentTab]);

  return (
    <div className="absolute bottom-0 left-0 right-0 z-50 bg-gradient-to-t from-black via-black/90 to-transparent pt-6">
      <div className="border-t border-term-amber/30 bg-term-grid/90 backdrop-blur-md relative">
        {/* Decorative corner markers */}
        <div className="absolute -top-1 left-0 w-2 h-2 border-l border-t border-term-amber"></div>
        <div className="absolute -top-1 right-0 w-2 h-2 border-r border-t border-term-amber"></div>

        {/* Scroll Container */}
        <div 
          ref={scrollRef}
          className="flex overflow-x-auto items-center px-2 py-1 scrollbar-hide snap-x"
          style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
          {tabs.map((tab) => {
            const isActive = currentTab === tab.id;
            const Icon = tab.icon;

            return (
              <button
                key={tab.id}
                data-active={isActive}
                onClick={() => onTabChange(tab.id)}
                className={`
                  relative flex flex-col items-center justify-center py-3 px-1 min-w-[20%] snap-center
                  transition-all duration-200 group
                  ${isActive ? 'text-term-amber' : 'text-term-gray hover:text-term-amber-dim'}
                `}
              >
                {isActive && (
                  <div className="absolute inset-x-1 inset-y-1 bg-term-amber/10 rounded border border-term-amber/20 shadow-[0_0_15px_rgba(255,176,0,0.1)]">
                    <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-term-amber shadow-[0_0_5px_#ffb000]"></div>
                  </div>
                )}

                <Icon className={`h-6 w-6 mb-1 transition-transform ${isActive ? 'scale-110 drop-shadow-[0_0_5px_rgba(255,176,0,0.5)]' : 'group-hover:scale-105'}`} />
                <span className="font-display text-[10px] tracking-widest uppercase truncate w-full text-center">{tab.label}</span>
              </button>
            );
          })}
        </div>

        {/* Decorative Scroll Indicators */}
        <div className="absolute bottom-0 left-0 w-4 h-full bg-gradient-to-r from-black to-transparent pointer-events-none"></div>
        <div className="absolute bottom-0 right-0 w-4 h-full bg-gradient-to-l from-black to-transparent pointer-events-none"></div>
      </div>
    </div>
  );
};

