import React, { useState } from 'react';
import { Item, PathType } from '../../types';
import { PATHS } from '../../data/paths';
import { getItem } from '../../data/items';

interface Props {
  items: string[];
  pathId: PathType;
}

type WeightUnit = 'KG' | 'LB';

export const InventoryView: React.FC<Props> = ({ items, pathId }) => {
  const [selectedItemIndex, setSelectedItemIndex] = useState<number | null>(null);
  const [weightUnit, setWeightUnit] = useState<WeightUnit>('KG');

  // Convert string list to detailed objects
  const inventoryItems = items.map((name, index) => ({
    ...getItem(name),
    uniqueId: `${index}_${name}` // Add unique ID for React keys if duplicate items exist
  }));

  const maxWeightKg = PATHS[pathId].carryCapacity;
  const currentWeightKg = inventoryItems.reduce((acc, item) => acc + item.weight, 0);

  // Conversion Helpers
  const displayWeight = (kg: number) => {
    if (weightUnit === 'KG') return kg.toFixed(1);
    return (kg * 2.20462).toFixed(1);
  };

  const getPercentage = () => Math.min(100, (currentWeightKg / maxWeightKg) * 100);

  const selectedItem = selectedItemIndex !== null ? inventoryItems[selectedItemIndex] : null;

  return (
    <div className="h-full flex flex-col p-4 pb-24 relative">
      {/* Header & Capacity */}
      <div className="flex flex-col gap-3 mb-6 border-b border-term-amber/30 pb-4">
         <div className="flex justify-between items-center">
            <h2 className="text-2xl font-display text-white">CARGO_HOLD</h2>
            <button 
              onClick={() => setWeightUnit(prev => prev === 'KG' ? 'LB' : 'KG')}
              className="text-xs font-bold border border-term-amber px-3 py-1.5 text-term-amber hover:bg-term-amber hover:text-black transition-colors rounded-sm"
            >
              UNIT: {weightUnit}
            </button>
         </div>

         {/* Weight Bar */}
         <div className="w-full mt-2">
            <div className="flex justify-between text-xs text-term-gray font-mono mb-2">
               <span>LOAD: {displayWeight(currentWeightKg)} {weightUnit}</span>
               <span>MAX: {displayWeight(maxWeightKg)} {weightUnit}</span>
            </div>
            <div className="h-3 bg-term-grid border border-term-gray w-full relative rounded-sm overflow-hidden">
               <div 
                 className={`h-full transition-all duration-500 ${getPercentage() > 90 ? 'bg-term-red animate-pulse' : 'bg-term-amber'}`} 
                 style={{ width: `${getPercentage()}%` }}
               ></div>
               {/* Tick marks */}
               <div className="absolute inset-0 flex justify-between px-1">
                 {[...Array(10)].map((_, i) => <div key={i} className="w-[1px] h-full bg-black/50"></div>)}
               </div>
            </div>
         </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-4 gap-3 md:gap-4 flex-1 content-start overflow-y-auto min-h-0 pr-1">
        {Array.from({ length: 20 }).map((_, i) => {
          const item = inventoryItems[i];
          const isSelected = selectedItemIndex === i;

          return (
            <div 
              key={i} 
              onClick={() => item && setSelectedItemIndex(i)}
              className={`
                aspect-square border relative group cursor-pointer transition-all duration-200 rounded-sm
                ${isSelected 
                  ? 'border-term-amber bg-term-amber/20 shadow-[0_0_15px_rgba(255,176,0,0.3)] scale-105 z-10' 
                  : 'border-term-gray bg-term-grid/50 hover:border-term-amber-dim hover:bg-term-amber/5'}
              `}
            >
               <div className="absolute top-1 left-1 text-[8px] text-term-gray group-hover:text-term-amber font-mono">
                 {i < 9 ? `0${i+1}` : i+1}
               </div>

               {item ? (
                 <div className="h-full w-full flex flex-col items-center justify-center p-2 text-center">
                    {/* Rarity Indicator */}
                    <div className={`w-2 h-2 rounded-full mb-2 ${
                      item.rarity === 'LEGENDARY' ? 'bg-purple-500 shadow-[0_0_8px_purple]' :
                      item.rarity === 'PROTOTYPE' ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' :
                      item.rarity === 'MIL-SPEC' ? 'bg-blue-500 shadow-[0_0_5px_blue]' : 
                      'bg-term-gray'
                    }`}></div>

                    <span className={`text-[10px] leading-tight font-bold ${
                      item.rarity === 'LEGENDARY' ? 'text-purple-300' :
                      item.rarity === 'PROTOTYPE' ? 'text-cyan-200' :
                      item.rarity === 'MIL-SPEC' ? 'text-blue-300' : 
                      'text-term-amber'
                    }`}>
                      {item.name}
                    </span>
                 </div>
               ) : (
                 <div className="h-full w-full flex items-center justify-center opacity-10">
                    <div className="w-2 h-2 border border-term-gray"></div>
                 </div>
               )}
            </div>
          );
        })}
      </div>

      {/* Detail Panel Popup (Bottom) */}
      <div className={`
        absolute bottom-24 left-4 right-4 border border-term-amber bg-black/95 p-5 z-20 backdrop-blur-md transform transition-all duration-300 shadow-2xl rounded-lg
        ${selectedItem ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0 pointer-events-none'}
      `}>
         {selectedItem && (
           <>
             <div className="flex justify-between items-start mb-3">
                <div>
                   <h3 className={`font-display text-xl ${
                      selectedItem.rarity === 'LEGENDARY' ? 'text-purple-400' :
                      selectedItem.rarity === 'PROTOTYPE' ? 'text-cyan-400' :
                      selectedItem.rarity === 'MIL-SPEC' ? 'text-blue-400' : 
                      'text-term-amber'
                   }`}>
                     {selectedItem.name}
                   </h3>
                   <div className="text-xs text-term-gray font-mono uppercase mt-1">
                      {selectedItem.type} // {selectedItem.rarity}
                   </div>
                </div>
                <div className="text-right">
                   <div className="text-2xl font-display text-white">{displayWeight(selectedItem.weight)} <span className="text-sm text-term-gray">{weightUnit}</span></div>
                   <button onClick={() => setSelectedItemIndex(null)} className="text-[10px] text-term-red hover:underline mt-1 block w-full text-right">CLOSE</button>
                </div>
             </div>

             <div className="text-sm text-stone-300 font-mono mb-6 border-l-2 border-term-gray pl-3 py-1">
                "{selectedItem.description}"
             </div>

             <div className="flex gap-4">
                <button className="flex-1 bg-term-amber text-black font-bold text-sm py-3 hover:bg-white transition-colors rounded-sm">EQUIP</button>
                <button className="flex-1 border border-term-red text-term-red font-bold text-sm py-3 hover:bg-term-red hover:text-black transition-colors rounded-sm">DROP</button>
             </div>
           </>
         )}
      </div>

      {!selectedItem && (
        <div className="mt-auto pt-4 px-2 pb-2 text-xs text-term-gray font-mono text-center animate-pulse">
            SELECT AN ITEM TO ACCESS METADATA
        </div>
      )}
    </div>
  );
};

import React from 'react';

const REPUTATION_TIERS = [
  { val: -1000, label: 'KILL ON SIGHT', color: 'text-term-red border-term-red bg-term-red' },
  { val: -500, label: 'HUNTED', color: 'text-orange-600 border-orange-600 bg-orange-600' },
  { val: -250, label: 'DESPISED', color: 'text-orange-400 border-orange-400 bg-orange-400' },
  { val: -125, label: 'HATED', color: 'text-yellow-600 border-yellow-600 bg-yellow-600' },
  { val: -75, label: 'DISLIKED', color: 'text-yellow-500 border-yellow-500 bg-yellow-500' },
  { val: 0, label: 'NEUTRAL', color: 'text-term-gray border-term-gray bg-term-gray' },
  { val: 75, label: 'LIKED', color: 'text-emerald-300 border-emerald-300 bg-emerald-300' },
  { val: 125, label: 'RESPECTED', color: 'text-emerald-500 border-emerald-500 bg-emerald-500' },
  { val: 250, label: 'REVERED', color: 'text-cyan-400 border-cyan-400 bg-cyan-400' },
  { val: 500, label: 'INFLUENTIAL', color: 'text-blue-500 border-blue-500 bg-blue-500' },
  { val: 1000, label: 'GAME_CHANGER', color: 'text-purple-500 border-purple-500 bg-purple-500 shadow-[0_0_10px_purple]' },
];

const getTier = (rep: number) => {
  // Find the closest tier that is <= the current rep, or the lowest tier
  for (let i = REPUTATION_TIERS.length - 1; i >= 0; i--) {
    if (rep >= REPUTATION_TIERS[i].val) return REPUTATION_TIERS[i];
  }
  return REPUTATION_TIERS[0];
};

const FACTIONS = [
  { id: 'gov', name: 'NEW WARSAW GOV', desc: 'Remnants of the old bureaucracy holding the city center.', rep: -150 },
  { id: 'scav', name: 'SCAVENGER UNION', desc: 'Loose collective of traders and thieves.', rep: 300 },
  { id: 'atom', name: 'CULT OF THE ATOM', desc: 'Worshippers of the glow. They occupy the craters.', rep: 800 },
  { id: 'nato', name: 'NATO REMNANT', desc: 'Military holdouts in the western districts.', rep: -900 },
];

export const ReputationView: React.FC = () => {
  return (
    <div className="h-full flex flex-col p-4 pb-24">
      <div className="mb-6 border-b border-term-amber/30 pb-4 flex justify-between items-end">
         <h2 className="text-2xl font-display text-white">POLITICAL_STANDING</h2>
         <span className="text-xs text-term-gray font-mono">GLOBAL_MODIFIER: 1.0x</span>
      </div>

      <div className="space-y-8 px-1 overflow-y-auto">
        {FACTIONS.map(faction => {
          const tier = getTier(faction.rep);
          const percent = (faction.rep + 1000) / 20; // Normalize -1000..1000 to 0..100

          return (
            <div key={faction.id} className="relative group bg-term-grid/30 p-3 rounded-lg border border-transparent hover:border-term-gray/50 transition-colors">
              <div className="flex justify-between items-center mb-2">
                <span className="font-display text-xl text-white">{faction.name}</span>
                <span className={`text-[10px] font-bold px-2 py-1 border rounded-sm ${tier.color} bg-black`}>
                  {tier.label} ({faction.rep})
                </span>
              </div>

              <div className="text-sm text-term-gray font-mono mb-4 leading-relaxed">
                {faction.desc}
              </div>

              {/* Progress Bar Container */}
              <div className="h-5 bg-black border border-term-gray/50 relative overflow-hidden rounded-sm">
                {/* Center Marker */}
                <div className="absolute left-1/2 top-0 bottom-0 w-[2px] bg-white/50 z-10"></div>

                {/* Bar */}
                <div 
                  className={`h-full transition-all duration-1000 ease-out opacity-80 ${tier.color.split(' ').pop()}`}
                  style={{ width: `${percent}%` }}
                ></div>

                {/* Grid Lines */}
                <div className="absolute inset-0 flex justify-between px-1">
                   {[...Array(20)].map((_, i) => <div key={i} className="w-[1px] h-full bg-white/10"></div>)}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="mt-auto p-4 border-t border-term-amber/20 bg-term-grid/50 rounded-lg">
        <div className="text-xs text-term-amber-dim font-bold mb-2">TIER LEGEND</div>
        <div className="flex flex-wrap gap-2">
           {REPUTATION_TIERS.filter((_, i) => i % 2 === 0).map(t => (
             <span key={t.val} className={`text-[9px] px-1.5 py-0.5 border rounded ${t.color.replace('text-', 'border-').split(' ')[1]} text-term-gray`}>
               {t.label}
             </span>
