import React, { useState, useEffect } from 'react';
import { PlayerStats, GameLocation, INITIAL_STATS_TEMPLATE, TabView, PathType } from './types';
import { PATHS } from './data/paths';
import { Dock } from './components/Dock';
import { StatusView } from './components/views/StatusView';
import { MapView } from './components/views/MapView';
import { InventoryView } from './components/views/InventoryView';
import { CommsView } from './components/views/CommsView';
import { CreationView } from './components/views/CreationView';
import { ReputationView } from './components/views/ReputationView';
import { RelationshipsView } from './components/views/RelationshipsView';
import { ArchivesView } from './components/views/ArchivesView';
import { FabricationView } from './components/views/FabricationView';
import { LOCATIONS } from './data/world';

type GameState = 'BOOT' | 'CREATION' | 'GAME';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>('BOOT');
  const [currentTab, setCurrentTab] = useState<TabView>(TabView.STATUS);
  const [stats, setStats] = useState<PlayerStats>(INITIAL_STATS_TEMPLATE);
  const [playerPath, setPlayerPath] = useState<PathType | null>(null);
  const [playerCodename, setPlayerCodename] = useState<string>('');
  const [currentLocId, setCurrentLocId] = useState<string>('start_bunker');
  const [inventory, setInventory] = useState<string[]>([]);

  useEffect(() => {
    const timer = setTimeout(() => setGameState('CREATION'), 3000);
    return () => clearTimeout(timer);
  }, []);

  const handleCharacterCreated = (pathId: PathType, codename: string, nationality?: string) => {
    const pathConfig = PATHS[pathId];
    const newStats: PlayerStats = {
      ...INITIAL_STATS_TEMPLATE,
      attributes: { ...pathConfig.baseStats },
      customMeters: []
    };

    if (pathId === 'THE_PSYCHO') {
      newStats.customMeters.push(
        { id: 'bloodlust', label: 'BLOODLUST', value: 0, max: 100, color: 'bg-term-red', decayRate: 1 },
        { id: 'psychosis', label: 'PSYCHOSIS', value: 10, max: 100, color: 'bg-purple-600' }
      );
    }
    if (pathId === 'THE_WANDERER') {
      newStats.customMeters.push(
        { id: 'stress', label: 'STRESS', value: 0, max: 100, color: 'bg-white' }
      );
    }

    let items = [...pathConfig.startingItems];
    if (pathId === 'THE_SNIPER' && nationality) {
      if (nationality === 'USA') items.push('M2010 Enhanced');
      if (nationality === 'RUSSIA') items.push('SV-98M');
      if (nationality === 'CHINA') items.push('QBU-10');
      items.push('Ballistic Drop Calculator');
    }

    setStats(newStats);
    setPlayerPath(pathId);
    setPlayerCodename(codename);
    setInventory(items);
    setGameState('GAME');
  };

  const handleTravel = (locId: string) => {
    setCurrentLocId(locId);
    setCurrentTab(TabView.STATUS); 
    if (playerPath === 'THE_WANDERER') {
       setStats(prev => ({
         ...prev,
         customMeters: prev.customMeters.map(m => m.id === 'stress' ? {...m, value: Math.max(0, m.value - 10)} : m)
       }));
    }
  };

  const renderContent = () => {
    const currentLocation = LOCATIONS[currentLocId] || LOCATIONS['start_bunker'];

    switch (currentTab) {
      case TabView.STATUS: return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
      case TabView.MAP: return <MapView currentLocationId={currentLocId} onTravel={handleTravel} />;
      case TabView.GEAR: return <InventoryView items={inventory} pathId={playerPath!} />;
      case TabView.COMMS: return <CommsView />;
      case TabView.REPUTATION: return <ReputationView />;
      case TabView.RELATIONS: return <RelationshipsView />;
      case TabView.ARCHIVES: return <ArchivesView />;
      case TabView.FABRICATION: return <FabricationView />;
      default: return <StatusView stats={stats} location={currentLocation} pathId={playerPath!} />;
    }
  };

  const BootSequence = () => (
    <div className="w-full h-full flex flex-col items-center justify-center bg-black p-8 font-mono relative overflow-hidden">
      <div className="absolute inset-0 bg-[repeating-linear-gradient(0deg,transparent,transparent_2px,#111_3px)] opacity-50"></div>
      <div className="font-display text-5xl animate-pulse tracking-[0.2em] text-term-red mb-8">FATAL_ERROR</div>
      <div className="w-64 h-4 bg-term-gray border border-term-gray rounded-sm overflow-hidden mb-2">
         <div className="h-full bg-term-amber animate-[width_2.5s_ease-in-out_forwards]" style={{width: '0%'}}></div>
      </div>
      <div className="font-mono text-xs text-term-amber-dim space-y-1 text-left w-64">
         <p>> BIOS_CHECK... OK</p>
         <p>> RAD_SHIELD... FAIL</p>
         <p className="animate-pulse">> BOOTING SAFE_MODE...</p>
      </div>
    </div>
  );

  return (
    <div className="flex items-center justify-center min-h-screen w-full bg-[#080808] p-4 md:p-8 font-mono select-none">
      {/* Device Shell */}
      <div className="relative w-full max-w-[440px] h-[850px] bg-neutral-900 rounded-[30px] shadow-[0_20px_50px_rgba(0,0,0,0.8),inset_0_0_20px_rgba(0,0,0,1)] border-[4px] border-neutral-800 flex flex-col overflow-hidden ring-1 ring-white/5">

        {/* Physical Top Sensor Array */}
        <div className="flex-none h-16 bg-neutral-800 border-b border-black flex items-center justify-between px-6 relative z-50">
           {/* Screw */}
           <div className="w-3 h-3 rounded-full bg-neutral-700 shadow-[inset_1px_1px_2px_rgba(0,0,0,0.8)] border border-neutral-600 flex items-center justify-center">
             <div className="w-2 h-[1px] bg-neutral-900 transform rotate-45"></div>
           </div>

           {/* Brand / Model */}
           <div className="flex flex-col items-center">
              <div className="text-[10px] tracking-[0.3em] text-neutral-500 font-bold">MIL-OS v.2.4</div>
              <div className="w-12 h-1 bg-term-red/20 mt-1 rounded-full overflow-hidden">
                 <div className="h-full w-full bg-term-red animate-pulse origin-left"></div>
              </div>
           </div>

           {/* Speaker Grille */}
           <div className="flex gap-1">
             {[1,2,3].map(i => <div key={i} className="w-1 h-4 bg-black rounded-full shadow-[inset_0_0_2px_rgba(255,255,255,0.1)]"></div>)}
           </div>
        </div>

        {/* Screen Bezel */}
        <div className="flex-1 bg-black m-3 mb-0 rounded-t-xl relative overflow-hidden ring-2 ring-neutral-700 shadow-[inset_0_0_20px_rgba(0,0,0,1)]">
           <div className="crt-overlay"></div>
           <div className="crt-vignette"></div>
           <div className="scanline"></div>

           {/* Inner Screen Content */}
           <div className="absolute inset-0 z-10 flex flex-col">
              {gameState === 'BOOT' ? <BootSequence /> : (
                <>
                  {/* Digital Header */}
                  <header className="flex-none flex items-end justify-between border-b border-term-amber/20 bg-term-amber/5 p-3 backdrop-blur-sm">
                    <div className="flex flex-col">
                        <span className="text-[9px] text-term-amber-dim font-bold tracking-widest">NET_UPLINK: ACTIVE</span>
                        <div className="flex items-center gap-2">
                          <span className="font-display text-xl tracking-widest glow-text text-white">WHF-2052</span>
                          <span className="text-[10px] px-1 bg-term-red text-black font-bold animate-pulse">REC</span>
                        </div>
                    </div>
                    <div className="text-right">
                        <div className="text-[9px] text-term-gray mb-0.5">OPERATOR</div>
                        <div className="text-xs text-term-amber font-bold border border-term-amber/30 px-2 py-0.5 bg-black/50 rounded-sm">
                          {playerCodename ? playerCodename : (playerPath ? PATHS[playerPath].name.toUpperCase() : 'UNKNOWN')}
                        </div>
                    </div>
                  </header>

                  <main className="flex-1 relative overflow-hidden bg-[radial-gradient(circle_at_center,rgba(20,20,20,1)_0%,rgba(0,0,0,1)_100%)]">
                    {gameState === 'CREATION' ? (
                        <CreationView onComplete={handleCharacterCreated} />
                    ) : (
                        <div className="absolute inset-0 pb-20 overflow-y-auto scrollbar-thin scrollbar-thumb-term-amber scrollbar-track-term-gray">
                            {renderContent()}
                        </div>
                    )}
                  </main>

                  {/* Dock Overlay */}
                  {gameState === 'GAME' && <Dock currentTab={currentTab} onTabChange={setCurrentTab} />}
                </>
              )}
           </div>
        </div>

        {/* Physical Bottom Chin */}
        <div className="flex-none h-12 bg-neutral-800 border-t border-black flex items-center justify-center gap-8 px-6 relative z-50">
           {/* Bolts */}
           <div className="absolute bottom-3 left-4 w-3 h-3 rounded-full bg-neutral-700 shadow-[inset_1px_1px_2px_rgba(0,0,0,0.8)] border border-neutral-600 flex items-center justify-center">
             <div className="w-2 h-[1px] bg-neutral-900 transform rotate-12"></div>
           </div>
           <div className="absolute bottom-3 right-4 w-3 h-3 rounded-full bg-neutral-700 shadow-[inset_1px_1px_2px_rgba(0,0,0,0.8)] border border-neutral-600 flex items-center justify-center">
             <div className="w-2 h-[1px] bg-neutral-900 transform rotate-90"></div>
           </div>

           {/* Decorative Port */}
           <div className="w-24 h-4 bg-black rounded-sm border border-neutral-600 shadow-[inset_0_2px_4px_rgba(0,0,0,0.8)] flex items-center justify-center gap-1">
              <div className="w-[2px] h-2 bg-neutral-600"></div>
              <div className="w-[2px] h-2 bg-neutral-600"></div>
              <div className="w-[2px] h-2 bg-neutral-600"></div>
              <div className="w-[2px] h-2 bg-neutral-600"></div>
           </div>
        </div>

      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { TabView } from '../types';
import { 
  IconStatus, IconMap, IconGear, IconComms, 
  IconReputation, IconRelations, IconArchives, IconFabrication 
} from './icons/DockIcons';

interface DockProps {
  currentTab: TabView;
  onTabChange: (tab: TabView) => void;
}

export const Dock: React.FC<DockProps> = ({ currentTab, onTabChange }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  const tabs = [
    { id: TabView.STATUS, label: 'BIO', icon: IconStatus },
    { id: TabView.MAP, label: 'NAV', icon: IconMap },
    { id: TabView.GEAR, label: 'GEAR', icon: IconGear },
    { id: TabView.FABRICATION, label: 'FAB', icon: IconFabrication },
    { id: TabView.REPUTATION, label: 'REP', icon: IconReputation },
    { id: TabView.RELATIONS, label: 'SOC', icon: IconRelations },
    { id: TabView.ARCHIVES, label: 'DAT', icon: IconArchives },
    { id: TabView.COMMS, label: 'NET', icon: IconComms },
  ];

  useEffect(() => {
    if (scrollRef.current) {
      const activeBtn = scrollRef.current.querySelector('[data-active="true"]');
      if (activeBtn) {
        activeBtn.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentTab]);

  return (
    <div className="absolute bottom-4 left-4 right-4 z-50">
      {/* Dock Container mimicking a physical keypad overlay */}
      <div className="bg-neutral-900/90 border border-neutral-700 rounded-lg p-2 backdrop-blur-md shadow-[0_10px_20px_rgba(0,0,0,0.8)]">

        <div 
          ref={scrollRef}
          className="flex overflow-x-auto gap-2 scrollbar-hide snap-x"
          style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
          {tabs.map((tab) => {
            const isActive = currentTab === tab.id;
            const Icon = tab.icon;

            return (
              <button
                key={tab.id}
                data-active={isActive}
                onClick={() => onTabChange(tab.id)}
                className={`
                  relative flex flex-col items-center justify-center p-3 min-w-[64px] snap-center rounded-md
                  transition-all duration-100 border-b-4 active:border-b-0 active:translate-y-1
                  ${isActive 
                    ? 'bg-term-amber text-black border-term-amber-dim shadow-[0_0_15px_rgba(255,176,0,0.4)]' 
                    : 'bg-neutral-800 text-term-gray border-black hover:bg-neutral-700 hover:text-term-amber'}
                `}
              >
                <Icon className={`h-6 w-6 mb-1 ${isActive ? 'scale-110' : 'opacity-50'}`} />
                <span className="font-mono text-[9px] font-bold tracking-wider">{tab.label}</span>

                {/* LED Indicator */}
                <div className={`
                   absolute top-1 right-1 w-1.5 h-1.5 rounded-full 
                   ${isActive ? 'bg-red-500 shadow-[0_0_5px_red] animate-pulse' : 'bg-black'}
                `}></div>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Item, PathType } from '../../types';
import { PATHS } from '../../data/paths';
import { getItem } from '../../data/items';

interface Props {
  items: string[];
  pathId: PathType;
}

type WeightUnit = 'KG' | 'LB';

export const InventoryView: React.FC<Props> = ({ items, pathId }) => {
  const [selectedItemIndex, setSelectedItemIndex] = useState<number | null>(null);
  const [weightUnit, setWeightUnit] = useState<WeightUnit>('KG');

  const inventoryItems = items.map((name, index) => ({
    ...getItem(name),
    uniqueId: `${index}_${name}`
  }));

  const maxWeightKg = PATHS[pathId].carryCapacity;
  const currentWeightKg = inventoryItems.reduce((acc, item) => acc + item.weight, 0);

  const displayWeight = (kg: number) => {
    if (weightUnit === 'KG') return kg.toFixed(1);
    return (kg * 2.20462).toFixed(1);
  };

  const getPercentage = () => Math.min(100, (currentWeightKg / maxWeightKg) * 100);
  const selectedItem = selectedItemIndex !== null ? inventoryItems[selectedItemIndex] : null;

  return (
    <div className="h-full flex flex-col p-6 pb-32 relative">
      {/* Manifest Header */}
      <div className="border border-term-gray bg-black p-4 mb-4 relative">
         <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-term-amber"></div>
         <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-term-amber"></div>
         <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-term-amber"></div>
         <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-term-amber"></div>

         <div className="flex justify-between items-start mb-2">
            <div>
               <h2 className="text-2xl font-display text-white tracking-widest">MANIFEST</h2>
               <div className="text-[10px] text-term-gray">CARGO_ID: 884-A</div>
            </div>
            <button 
              onClick={() => setWeightUnit(prev => prev === 'KG' ? 'LB' : 'KG')}
              className="text-[9px] font-bold border border-term-amber/50 px-2 py-1 text-term-amber hover:bg-term-amber hover:text-black transition-colors uppercase"
            >
              Toggle Unit ({weightUnit})
            </button>
         </div>

         {/* Weight Gauge */}
         <div className="w-full mt-2">
            <div className="flex justify-between text-[10px] text-stone-500 font-mono mb-1">
               <span>CAPACITY UTILIZATION</span>
               <span>{displayWeight(currentWeightKg)} / {displayWeight(maxWeightKg)} {weightUnit}</span>
            </div>
            <div className="h-4 bg-term-grid border border-stone-800 w-full relative p-[2px]">
               <div className="w-full h-full relative overflow-hidden">
                   {/* Striped Pattern */}
                   <div 
                     className={`h-full transition-all duration-500 ${getPercentage() > 90 ? 'bg-term-red' : 'bg-term-amber'} opacity-80`} 
                     style={{ 
                         width: `${getPercentage()}%`,
                         backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 5px, rgba(0,0,0,0.3) 5px, rgba(0,0,0,0.3) 10px)'
                     }}
                   ></div>
               </div>
            </div>
         </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-4 gap-2 md:gap-3 flex-1 content-start overflow-y-auto min-h-0 pr-1 pb-2">
        {Array.from({ length: 20 }).map((_, i) => {
          const item = inventoryItems[i];
          const isSelected = selectedItemIndex === i;

          return (
            <div 
              key={i} 
              onClick={() => item && setSelectedItemIndex(i)}
              className={`
                aspect-square border relative group cursor-pointer transition-all duration-100
                ${isSelected 
                  ? 'border-term-amber bg-term-amber/10 shadow-[inset_0_0_10px_rgba(255,176,0,0.2)]' 
                  : 'border-stone-800 bg-black hover:border-stone-600'}
              `}
            >
               <div className="absolute top-0.5 left-1 text-[7px] text-stone-700 font-mono">
                 {i < 9 ? `0${i+1}` : i+1}
               </div>

               {item ? (
                 <div className="h-full w-full flex flex-col items-center justify-center p-2 text-center">
                    {/* Rarity Dot */}
                    <div className={`w-1.5 h-1.5 rounded-sm mb-2 rotate-45 ${
                      item.rarity === 'LEGENDARY' ? 'bg-purple-500 shadow-[0_0_8px_purple]' :
                      item.rarity === 'PROTOTYPE' ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' :
                      item.rarity === 'MIL-SPEC' ? 'bg-blue-500 shadow-[0_0_5px_blue]' : 
                      'bg-term-gray'
                    }`}></div>

                    <span className={`text-[9px] leading-tight font-bold uppercase ${
                      item.rarity === 'LEGENDARY' ? 'text-purple-300' :
                      item.rarity === 'PROTOTYPE' ? 'text-cyan-200' :
                      item.rarity === 'MIL-SPEC' ? 'text-blue-300' : 
                      'text-stone-400 group-hover:text-term-amber'
                    }`}>
                      {item.name}
                    </span>
                 </div>
               ) : (
                 <div className="h-full w-full flex items-center justify-center">
                    <div className="w-1 h-1 bg-stone-900 rounded-full"></div>
                 </div>
               )}
            </div>
          );
        })}
      </div>

      {/* Detail Panel Overlay */}
      <div className={`
        absolute bottom-28 left-2 right-2 border-2 border-neutral-700 bg-[#111] p-4 z-20 shadow-2xl transition-all duration-300
        ${selectedItem ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0 pointer-events-none'}
      `}>
         {selectedItem && (
           <>
             <div className="flex justify-between items-start mb-3 border-b border-white/10 pb-2">
                <div className="flex flex-col">
                   <h3 className={`font-display text-xl tracking-wide ${
                      selectedItem.rarity === 'LEGENDARY' ? 'text-purple-400' :
                      selectedItem.rarity === 'PROTOTYPE' ? 'text-cyan-400' :
                      selectedItem.rarity === 'MIL-SPEC' ? 'text-blue-400' : 
                      'text-term-amber'
                   }`}>
                     {selectedItem.name}
                   </h3>
                   <span className="text-[9px] text-stone-500 font-mono uppercase bg-black px-1 self-start border border-stone-800 mt-1">
                      {selectedItem.type} // {selectedItem.rarity}
                   </span>
                </div>
                <div className="text-right font-mono text-white">
                   <div className="text-lg">{displayWeight(selectedItem.weight)} <span className="text-[10px] text-stone-500">{weightUnit}</span></div>
                </div>
             </div>

