                group relative flex flex-col items-center justify-center px-4 py-3 min-w-[80px] rounded-lg transition-all duration-200 border
                ${isActive 
                  ? 'bg-white/10 border-white/40 text-white shadow-[inset_0_0_20px_rgba(255,255,255,0.1)] translate-y-0.5' 
                  : 'bg-transparent border-transparent text-stone-500 hover:text-white hover:bg-white/5'}
              `}
            >
              <Icon className={`h-6 w-6 mb-2 transition-transform ${isActive ? 'scale-110 drop-shadow-[0_0_8px_currentColor]' : 'scale-100'}`} />
              <span className="font-mono text-[9px] font-bold tracking-widest">{tab.label}</span>

              {/* Active Indicator Light */}
              <div className={`
                 absolute top-2 right-2 w-1 h-1 rounded-full
                 ${isActive ? 'bg-current shadow-[0_0_5px_currentColor] animate-pulse' : 'bg-black'}
              `}></div>
            </button>
          );
        })}
      </div>
    </div>
  );
};

