export const ArchivesView: React.FC = () => {
  const [selectedEntry, setSelectedEntry] = useState<number | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playbackProgress, setPlaybackProgress] = useState(0);
  const animationRef = useRef<number | null>(null);

  const currentFile = ENTRIES.find(e => e.id === selectedEntry);

  useEffect(() => {
    // Cleanup speech on unmount
    return () => {
      window.speechSynthesis.cancel();
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, []);

  const handlePlay = (text: string) => {
    window.speechSynthesis.cancel();

    if (isPlaying && currentFile?.content === text) {
      setIsPlaying(false);
      setPlaybackProgress(0);
      return;
    }

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.rate = 0.9;
    utterance.pitch = 0.8;
    // Try to find a robotic or deep voice
    const voices = window.speechSynthesis.getVoices();
    const systemVoice = voices.find(v => v.name.includes('Google US English') || v.name.includes('Microsoft David')) || voices[0];
    if (systemVoice) utterance.voice = systemVoice;

    utterance.onstart = () => {
      setIsPlaying(true);
      animateProgress();
    };
    utterance.onend = () => {
      setIsPlaying(false);
      setPlaybackProgress(100);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };

    window.speechSynthesis.speak(utterance);
  };

  const animateProgress = () => {
    setPlaybackProgress(prev => {
      if (prev >= 100) return 0;
      return prev + 0.5;
    });
    animationRef.current = requestAnimationFrame(animateProgress);
  };

  return (
    <div className="h-full flex flex-col md:flex-row gap-4 p-4">
      {/* Directory List */}
      <div className="flex-1 border border-white/20 bg-black/50 p-4 overflow-y-auto">
        <div className="text-xs text-stone-500 font-mono mb-4 border-b border-white/10 pb-2">
           ROOT:/SYSTEM/LOGS/ARCHIVE_2052/
        </div>

        <div className="space-y-1">
          {ENTRIES.map(entry => (
            <button 
              key={entry.id} 
              onClick={() => {
                setSelectedEntry(entry.id);
                setIsPlaying(false);
                window.speechSynthesis.cancel();
                setPlaybackProgress(0);
              }}
              className={`w-full flex items-center gap-3 p-2 font-mono text-left transition-all border border-transparent
                ${selectedEntry === entry.id 
                  ? 'bg-white/10 border-white/30 text-white' 
                  : 'text-stone-400 hover:text-white hover:bg-white/5'}
              `}
            >
               <div className={`w-2 h-2 ${selectedEntry === entry.id ? 'bg-current animate-pulse' : 'bg-stone-700'}`}></div>
               <div className="flex-1">
                  <div className="text-sm tracking-wider">{entry.title}</div>
                  <div className="text-[10px] opacity-50">{entry.date} | {entry.type}</div>
               </div>
               <div className="text-[10px] border border-current px-1 opacity-70">{entry.status}</div>
            </button>
          ))}
        </div>
      </div>

      {/* File Viewer / Reader */}
      <div className="flex-[1.5] border border-white/20 bg-black p-6 relative flex flex-col">
        {currentFile ? (
          <>
             <div className="flex justify-between items-start mb-6 border-b-2 border-dashed border-stone-800 pb-4">
                <div>
                   <h2 className="text-2xl font-display tracking-widest text-white mb-1">{currentFile.title}</h2>
                   <div className="text-xs font-mono text-stone-500">
                      SIZE: {currentFile.content.length * 12} BYTES // ENC: {currentFile.status}
                   </div>
                </div>
                {/* Play Button */}
                <button 
                   onClick={() => handlePlay(currentFile.content)}
                   className={`
                     w-12 h-12 flex items-center justify-center border transition-all
                     ${isPlaying 
                        ? 'border-red-500 text-red-500 animate-pulse' 
                        : 'border-white/30 text-white hover:border-white hover:bg-white/10'}
                   `}
                >
                   {isPlaying ? (
                     <div className="w-4 h-4 bg-current"></div>
                   ) : (
                     <div className="w-0 h-0 border-t-[8px] border-t-transparent border-l-[14px] border-l-current border-b-[8px] border-b-transparent ml-1"></div>
                   )}
                </button>
             </div>

             {/* Content Area */}
             <div className="flex-1 font-mono text-sm leading-relaxed text-stone-300 overflow-y-auto whitespace-pre-wrap">
                {isPlaying ? (
                   <span className="text-white drop-shadow-[0_0_5px_rgba(255,255,255,0.5)]">
                      {currentFile.content}
                   </span>
                ) : (
                   currentFile.content
                )}
             </div>

             {/* Visualizer / Status Footer */}
             <div className="mt-4 h-12 border border-stone-800 bg-stone-900/50 flex items-end gap-[2px] p-1 overflow-hidden">
                {isPlaying ? (
                  Array.from({length: 40}).map((_, i) => (
                    <div 
                      key={i} 
                      className="flex-1 bg-current opacity-50 transition-all duration-75"
                      style={{ height: `${Math.random() * 100}%` }}
                    ></div>
                  ))
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-[10px] text-stone-600">
                    AWAITING PLAYBACK INPUT...
                  </div>
                )}
             </div>
          </>
        ) : (
           <div className="flex-1 flex flex-col items-center justify-center text-stone-600">
              <div className="text-4xl mb-4 opacity-20 font-display">NO_DATA_SELECTED</div>
              <div className="text-xs font-mono">Select a file from the directory to decrypt.</div>
           </div>
        )}
      </div>
    </div>
  );
};

export enum TabView {
  STATUS = 'STATUS',
  MAP = 'MAP',
  GEAR = 'GEAR',
  COMMS = 'COMMS',
  REPUTATION = 'REPUTATION',
  RELATIONS = 'RELATIONS',
  ARCHIVES = 'ARCHIVES',
  FABRICATION = 'FABRICATION',
}

export type PathType = 'THE_VOICE' | 'THE_TRAITOR' | 'THE_WANDERER' | 'THE_PSYCHO' | 'THE_CANNIBAL' | 'THE_SNIPER';

export interface Trait {
  id: string;
  name: string;
  description: string;
  effect: string; // Description of gameplay effect
}

export interface Subclass {
  id: string; // e.g., 'bloodgut'
  name: string; // e.g., 'Bloodgut'
  description: string; // Flavor text
  mechanic: string; // The actual effect description
}

export interface Meter {
  id: string;
  label: string;
  value: number;
  max: number;
  color: string;
  decayRate?: number; // Per tick
}

export interface PlayerStats {
  hp: number;
  maxHp: number;
  rads: number;
  hunger: number;
  level: number;
  exp: number;
  nextLevelExp: number;
  // Stats are now dynamic keys based on Path
  attributes: Record<string, number>;
  // Meters specific to the class (e.g. Psychosis, Stress, Bloodlust)
  customMeters: Meter[];
}

export interface PathConfig {
  id: PathType;
  name: string;
  description: string;
  // Attributes now support variable length for Acronyms (e.g. W.H.I.S.P.E.R)
  attributeLabels: string[]; 
  baseStats: Record<string, number>;
  startingTraits: Trait[];
  startingItems: string[]; // IDs of items
  subclasses: Subclass[]; // Replaces simple codenames list
  carryCapacity: number; // Base capacity in KG
}

export interface GameLocation {
  id: string;
  name: string;
  description: string;
  dangerLevel: number; // 1-5
  coordinates: { x: number; y: number };
  isUnlocked: boolean;
}

export interface Item {
  id: string;
  name: string;
  type: 'WEAPON' | 'ARMOR' | 'CONSUMABLE' | 'JUNK' | 'GADGET';
  rarity: 'COMMON' | 'MIL-SPEC' | 'PROTOTYPE' | 'LEGENDARY';
  description: string;
  weight: number; // in KG
}

