import React, { useState } from 'react';
import { Item, PathType } from '../../types';
import { PATHS } from '../../data/paths';
import { getItem } from '../../data/items';

interface Props {
  items: string[];
  pathId: PathType;
}

type WeightUnit = 'KG' | 'LB';

export const InventoryView: React.FC<Props> = ({ items, pathId }) => {
  const [selectedItemIndex, setSelectedItemIndex] = useState<number | null>(null);
  const [weightUnit, setWeightUnit] = useState<WeightUnit>('KG');

  const inventoryItems = items.map((name, index) => ({
    ...getItem(name),
    uniqueId: `${index}_${name}`
  }));

  const maxWeightKg = PATHS[pathId].carryCapacity;
  const currentWeightKg = inventoryItems.reduce((acc, item) => acc + item.weight, 0);

  const displayWeight = (kg: number) => {
    if (weightUnit === 'KG') return kg.toFixed(1);
    return (kg * 2.20462).toFixed(1);
  };

  const getPercentage = () => Math.min(100, (currentWeightKg / maxWeightKg) * 100);
  const selectedItem = selectedItemIndex !== null ? inventoryItems[selectedItemIndex] : null;

  return (
    <div className="h-full flex flex-col p-2 md:p-6 pb-28 md:pb-32 relative">
      {/* Manifest Header */}
      <div className="border border-term-gray bg-black p-4 mb-4 relative">
         <div className="absolute top-0 left-0 w-2 h-2 border-t border-l border-term-amber"></div>
         <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-term-amber"></div>
         <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-term-amber"></div>
         <div className="absolute bottom-0 right-0 w-2 h-2 border-b border-r border-term-amber"></div>

         <div className="flex justify-between items-start mb-2">
            <div>
               <h2 className="text-xl md:text-2xl font-display text-white tracking-widest">MANIFEST</h2>
               <div className="text-[10px] text-term-gray">CARGO_ID: 884-A</div>
            </div>
            <button 
              onClick={() => setWeightUnit(prev => prev === 'KG' ? 'LB' : 'KG')}
              className="text-[8px] md:text-[9px] font-bold border border-term-amber/50 px-2 py-1 text-term-amber hover:bg-term-amber hover:text-black transition-colors uppercase"
            >
              Toggle Unit ({weightUnit})
            </button>
         </div>

         {/* Weight Gauge */}
         <div className="w-full mt-2">
            <div className="flex justify-between text-[10px] text-stone-500 font-mono mb-1">
               <span>CAPACITY UTILIZATION</span>
               <span>{displayWeight(currentWeightKg)} / {displayWeight(maxWeightKg)} {weightUnit}</span>
            </div>
            <div className="h-4 bg-term-grid border border-stone-800 w-full relative p-[2px]">
               <div className="w-full h-full relative overflow-hidden">
                   {/* Striped Pattern */}
                   <div 
                     className={`h-full transition-all duration-500 ${getPercentage() > 90 ? 'bg-term-red' : 'bg-term-amber'} opacity-80`} 
                     style={{ 
                         width: `${getPercentage()}%`,
                         backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 5px, rgba(0,0,0,0.3) 5px, rgba(0,0,0,0.3) 10px)'
                     }}
                   ></div>
               </div>
            </div>
         </div>
      </div>

      {/* Grid - Responsive columns */}
      <div className="grid grid-cols-3 sm:grid-cols-4 lg:grid-cols-6 gap-2 md:gap-3 flex-1 content-start overflow-y-auto min-h-0 pr-1 pb-2">
        {Array.from({ length: 24 }).map((_, i) => {
          const item = inventoryItems[i];
          const isSelected = selectedItemIndex === i;

          return (
            <div 
              key={i} 
              onClick={() => item && setSelectedItemIndex(i)}
              className={`
                aspect-square border relative group cursor-pointer transition-all duration-100
                ${isSelected 
                  ? 'border-term-amber bg-term-amber/10 shadow-[inset_0_0_10px_rgba(255,176,0,0.2)]' 
                  : 'border-stone-800 bg-black hover:border-stone-600'}
              `}
            >
               <div className="absolute top-0.5 left-1 text-[7px] text-stone-700 font-mono">
                 {i < 9 ? `0${i+1}` : i+1}
               </div>

               {item ? (
                 <div className="h-full w-full flex flex-col items-center justify-center p-2 text-center">
                    {/* Rarity Dot */}
                    <div className={`w-1.5 h-1.5 rounded-sm mb-2 rotate-45 ${
                      item.rarity === 'LEGENDARY' ? 'bg-purple-500 shadow-[0_0_8px_purple]' :
                      item.rarity === 'PROTOTYPE' ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' :
                      item.rarity === 'MIL-SPEC' ? 'bg-blue-500 shadow-[0_0_5px_blue]' : 
                      'bg-term-gray'
                    }`}></div>

                    <span className={`text-[8px] md:text-[9px] leading-tight font-bold uppercase ${
                      item.rarity === 'LEGENDARY' ? 'text-purple-300' :
                      item.rarity === 'PROTOTYPE' ? 'text-cyan-200' :
                      item.rarity === 'MIL-SPEC' ? 'text-blue-300' : 
                      'text-stone-400 group-hover:text-term-amber'
                    }`}>
                      {item.name}
                    </span>
                 </div>
               ) : (
                 <div className="h-full w-full flex items-center justify-center">
                    <div className="w-1 h-1 bg-stone-900 rounded-full"></div>
                 </div>
               )}
            </div>
          );
        })}
      </div>

      {/* Detail Panel Overlay - Mobile friendly positioning */}
      <div className={`
        absolute bottom-20 md:bottom-28 left-2 right-2 border-2 border-neutral-700 bg-[#111] p-4 z-20 shadow-2xl transition-all duration-300
        ${selectedItem ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0 pointer-events-none'}
      `}>
         {selectedItem && (
           <>
             <div className="flex justify-between items-start mb-3 border-b border-white/10 pb-2">
                <div className="flex flex-col">
                   <h3 className={`font-display text-lg md:text-xl tracking-wide ${
                      selectedItem.rarity === 'LEGENDARY' ? 'text-purple-400' :
                      selectedItem.rarity === 'PROTOTYPE' ? 'text-cyan-400' :
                      selectedItem.rarity === 'MIL-SPEC' ? 'text-blue-400' : 
                      'text-term-amber'
                   }`}>
                     {selectedItem.name}
                   </h3>
                   <span className="text-[9px] text-stone-500 font-mono uppercase bg-black px-1 self-start border border-stone-800 mt-1">
                      {selectedItem.type} // {selectedItem.rarity}
                   </span>
                </div>
                <div className="text-right font-mono text-white">
                   <div className="text-base md:text-lg">{displayWeight(selectedItem.weight)} <span className="text-[10px] text-stone-500">{weightUnit}</span></div>
                </div>
             </div>

             <div className="text-xs text-stone-400 font-mono mb-4 leading-relaxed max-h-20 overflow-y-auto">
                {selectedItem.description}
             </div>

             <div className="flex gap-2">
                <button className="flex-1 bg-term-amber text-black font-bold text-xs py-2 md:py-3 hover:bg-white transition-colors uppercase tracking-wider clip-corner">EQUIP ITEM</button>
                <button 
                  onClick={() => setSelectedItemIndex(null)}
                  className="px-4 border border-term-red text-term-red font-bold text-xs py-2 md:py-3 hover:bg-term-red hover:text-black transition-colors uppercase tracking-wider"
                >
                  CLOSE
                </button>
             </div>
           </>
         )}
      </div>
    </div>
  );
};

export enum TabView {
  STATUS = 'STATUS',
  MAP = 'MAP',
  GEAR = 'GEAR',
  COMMS = 'COMMS',
  REPUTATION = 'REPUTATION',
  RELATIONS = 'RELATIONS',
  ARCHIVES = 'ARCHIVES',
  FABRICATION = 'FABRICATION',
}

export type PathType = 'THE_VOICE' | 'THE_TRAITOR' | 'THE_WANDERER' | 'THE_PSYCHO' | 'THE_CANNIBAL' | 'THE_SNIPER';

export interface Trait {
  id: string;
  name: string;
  description: string;
  effect: string; // Description of gameplay effect
}

export interface Subclass {
  id: string; // e.g., 'bloodgut'
  name: string; // e.g., 'Bloodgut'
  description: string; // Flavor text
  mechanic: string; // The actual effect description
  trait: Trait; // The trait granted by this subclass
}

export interface Meter {
  id: string;
  label: string;
  value: number;
  max: number;
  color: string;
  decayRate?: number; // Per tick
}

export interface PlayerStats {
  hp: number;
  maxHp: number;
  rads: number;
  hunger: number;
  level: number;
  exp: number;
  nextLevelExp: number;
  // Stats are now dynamic keys based on Path
  attributes: Record<string, number>;
  // Meters specific to the class (e.g. Psychosis, Stress, Bloodlust)
  customMeters: Meter[];
}

export interface PathConfig {
  id: PathType;
  name: string;
  description: string;
  // Attributes now support variable length for Acronyms (e.g. W.H.I.S.P.E.R)
  attributeLabels: string[]; 
  baseStats: Record<string, number>;
  startingTraits: Trait[];
  startingItems: string[]; // IDs of items
  subclasses: Subclass[]; // Replaces simple codenames list
  carryCapacity: number; // Base capacity in KG
}

export interface GameLocation {
  id: string;
  name: string;
  description: string;
  dangerLevel: number; // 1-5
  coordinates: { x: number; y: number };
  isUnlocked: boolean;
}

export interface Item {
  id: string;
  name: string;
  type: 'WEAPON' | 'ARMOR' | 'CONSUMABLE' | 'JUNK' | 'GADGET';
  rarity: 'COMMON' | 'MIL-SPEC' | 'PROTOTYPE' | 'LEGENDARY';
  description: string;
  weight: number; // in KG
}

export const INITIAL_STATS_TEMPLATE: PlayerStats = {
  hp: 100,
  maxHp: 100,
  rads: 0,
  hunger: 0,
