                           <span className="text-[8px] md:text-[10px] opacity-70 tracking-widest">SIGNAL</span>
                           <div className="flex gap-0.5">
                              <div className={`w-0.5 md:w-1 h-1.5 md:h-2 ${activeTheme.accent}`}></div>
                              <div className={`w-0.5 md:w-1 h-1.5 md:h-2 ${activeTheme.accent}`}></div>
