import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, GenerateContentResponse } from '@google/genai';
import { SYSTEM_PROMPT } from '../../data/systemPrompt';

interface Message {
  id: number;
  sender: 'AI' | 'USER';
  text: string;
}

interface Props {
  introScenario?: string;
  pathName?: string;
  subclassName?: string;
}

export const GameView: React.FC<Props> = ({ introScenario, pathName, subclassName }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Initialize Gemini Client
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  useEffect(() => {
    // Only initialize once, and only if we have an introScenario (meaning game has started)
    if (!isInitialized && introScenario) {
      const initGame = async () => {
        setIsLoading(true);
        try {
          const startingPrompt = `Initialize the story. I am playing as a "${pathName}" (Subclass: ${subclassName}). The starting scene is: "${introScenario}". Describe the immediate surroundings and the situation to begin the game. Remember to follow all roleplay rules.`;

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: startingPrompt,
            config: {
              systemInstruction: SYSTEM_PROMPT,
            }
          });

          if (response.text) {
            setMessages([{
              id: Date.now(),
              sender: 'AI',
              text: response.text
            }]);
          }
          setIsInitialized(true);
        } catch (error) {
          console.error("Failed to initialize game:", error);
          setMessages([{
            id: Date.now(),
            sender: 'AI',
            text: "SYSTEM ERROR: Neural link unstable. Unable to connect to narrative engine. (Check API Key or Network)"
          }]);
        } finally {
          setIsLoading(false);
        }
      };

      initGame();
    }
  }, [isInitialized, introScenario, pathName, subclassName]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { id: Date.now(), sender: 'USER', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      // Build conversation history for context
      // Note: For a real long-running game, we'd need to manage token limits or use a ChatSession properly.
      // Here we'll just send the last few turns + system prompt context implied by the stateless call or use multi-turn chat

      // Better approach: Use chat session if possible, but let's stick to generateContent with history for simplicity if chat session state is hard to persist in this component structure
      // actually, ai.chats.create is better for history management.

      // Let's reconstruct the history for the API call
      // The first message from AI was generated by our specific prompt. 
      // We will treat previous messages as history.

      const history = messages.map(m => ({
        role: m.sender === 'USER' ? 'user' : 'model',
        parts: [{ text: m.text }]
      }));

      // Add the new user message
      history.push({ role: 'user', parts: [{ text: userMsg.text }] });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: history, // Pass full history
        config: {
          systemInstruction: SYSTEM_PROMPT,
        }
      });

      if (response.text) {
        setMessages(prev => [...prev, {
          id: Date.now(),
          sender: 'AI',
          text: response.text || "..."
        }]);
      }
    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, {
        id: Date.now(),
        sender: 'AI',
        text: "CONNECTION INTERRUPTED. (API Error)"
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="h-full w-full flex flex-col bg-black/80 relative overflow-hidden">
      {/* CRT Scanline Overlay is in global CSS, but we can add inner shadow here */}
      <div className="absolute inset-0 shadow-[inset_0_0_50px_rgba(0,0,0,0.8)] pointer-events-none z-10"></div>

      {/* Chat History */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scrollbar-thin scrollbar-thumb-term-gray scrollbar-track-transparent z-0">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex flex-col ${msg.sender === 'USER' ? 'items-end' : 'items-start'} animate-[fadeIn_0.3s_ease-out]`}
          >
            <div className={`
              max-w-[90%] md:max-w-[80%] p-3 md:p-4 font-mono text-sm md:text-base leading-relaxed whitespace-pre-wrap
              ${msg.sender === 'USER' 
                ? 'bg-term-amber/10 border border-term-amber/30 text-term-amber rounded-tl-lg rounded-bl-lg rounded-br-lg' 
                : 'bg-transparent text-stone-300 border-l-2 border-stone-700 pl-4'}
            `}>
              {msg.sender === 'AI' ? (
                // Parse simple markdown for bold/italic if needed, or just render text
                msg.text
              ) : (
                <span className="text-term-amber font-bold">> {msg.text}</span>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-2 text-term-amber/50 font-mono text-xs ml-4">
            <div className="w-2 h-2 bg-current animate-bounce"></div>
            <div className="w-2 h-2 bg-current animate-bounce delay-75"></div>
