import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from '@google/genai';
import { SYSTEM_PROMPT } from '../../data/systemPrompt';
import { GameStateUpdate } from '../../types';

interface Message {
  id: number;
  sender: 'AI' | 'USER';
  text: string;
}

interface Props {
  introScenario?: string;
  pathName?: string;
  subclassName?: string;
  onGameStateUpdate: (update: GameStateUpdate) => void;
}

export const GameView: React.FC<Props> = ({ introScenario, pathName, subclassName, onGameStateUpdate }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Initialize Gemini Client
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Helper function to process AI response (extract JSON, format text)
  const processAIResponse = (rawText: string) => {
    let cleanText = rawText;

    // 1. Extract JSON State Updates
    const jsonRegex = /<<<([\s\S]*?)>>>/;
    const jsonMatch = rawText.match(jsonRegex);

    if (jsonMatch && jsonMatch[1]) {
      try {
        const updateData = JSON.parse(jsonMatch[1]);
        console.log("Game State Update Received:", updateData);
        onGameStateUpdate(updateData);
        // Remove the JSON block from the text to display
        cleanText = rawText.replace(jsonRegex, '').trim();
      } catch (e) {
        console.error("Failed to parse game state JSON:", e);
      }
    }

    return cleanText;
  };

  useEffect(() => {
    // Only initialize once, and only if we have an introScenario (meaning game has started)
    if (!isInitialized && introScenario) {
      const initGame = async () => {
        setIsLoading(true);
        try {
          const startingPrompt = `Initialize the story. I am playing as a "${pathName}" (Subclass: ${subclassName}). The starting scene is: "${introScenario}". 

          TASK:
          1. Describe the immediate surroundings and the situation.
          2. Generate a UNIQUE MAIN QUEST based specifically on the Subclass ${subclassName}. Use the JSON format to add this quest to the UI immediately.
          3. If there are NPCs, use the ||COLOR|DESCRIPTOR|| format to introduce them.
          4. Follow all system roleplay rules.`;

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: startingPrompt,
            config: {
              systemInstruction: SYSTEM_PROMPT,
            }
          });

          if (response.text) {
            const processedText = processAIResponse(response.text);
            setMessages([{
              id: Date.now(),
              sender: 'AI',
              text: processedText
            }]);
          }
          setIsInitialized(true);
        } catch (error) {
          console.error("Failed to initialize game:", error);
          setMessages([{
            id: Date.now(),
            sender: 'AI',
            text: "SYSTEM ERROR: Neural link unstable. Unable to connect to narrative engine. (Check API Key or Network)"
          }]);
        } finally {
          setIsLoading(false);
        }
      };

      initGame();
    }
  }, [isInitialized, introScenario, pathName, subclassName]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { id: Date.now(), sender: 'USER', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({
        role: m.sender === 'USER' ? 'user' : 'model',
        parts: [{ text: m.text }]
      }));

      // Add the new user message
      history.push({ role: 'user', parts: [{ text: userMsg.text }] });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: history, // Pass full history
        config: {
          systemInstruction: SYSTEM_PROMPT,
        }
      });

      if (response.text) {
        const processedText = processAIResponse(response.text);
        setMessages(prev => [...prev, {
          id: Date.now(),
          sender: 'AI',
          text: processedText || "..."
        }]);
      }
    } catch (error) {
      console.error("AI Error:", error);
      setMessages(prev => [...prev, {
        id: Date.now(),
        sender: 'AI',
        text: "CONNECTION INTERRUPTED. (API Error)"
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Custom Renderer for NPC Dialogue Headers
  const renderMessageContent = (text: string) => {
    // Regex for: ||HEXCODE|DESCRIPTOR|| "Dialogue"
    // We split by newline to handle paragraphs, then check lines for patterns
    return text.split('\n').map((line, idx) => {
      const npcRegex = /\|\|(#[0-9a-fA-F]{6})\|(.*?)\|\|(.*)/;
      const match = line.match(npcRegex);

      if (match) {
        const color = match[1];
        const descriptor = match[2];
        const content = match[3];

        return (
          <div key={idx} className="mb-4 mt-2">
            <div 
              className="inline-block px-2 py-0.5 text-[10px] font-bold uppercase tracking-wider mb-1 border-l-2 bg-black/50"
              style={{ borderColor: color, color: color }}
            >
              {descriptor}
            </div>
            <div className="pl-2 italic text-stone-200">
              {content}
            </div>
          </div>
        );
      }

      // Render regular paragraphs
      if (line.trim() === '') return <br key={idx} />;
      return <p key={idx} className="mb-2">{line}</p>;
    });
  };

  return (
    <div className="h-full w-full flex flex-col bg-black/80 relative overflow-hidden">
      {/* CRT Scanline Overlay is in global CSS, but we can add inner shadow here */}
      <div className="absolute inset-0 shadow-[inset_0_0_50px_rgba(0,0,0,0.8)] pointer-events-none z-10"></div>

      {/* Chat History */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scrollbar-thin scrollbar-thumb-term-gray scrollbar-track-transparent z-0">
        {messages.map((msg) => (
          <div 
            key={msg.id} 
            className={`flex flex-col ${msg.sender === 'USER' ? 'items-end' : 'items-start'} animate-[fadeIn_0.3s_ease-out]`}
          >
            <div className={`
              max-w-[90%] md:max-w-[80%] p-3 md:p-4 font-mono text-sm md:text-base leading-relaxed whitespace-pre-wrap
              ${msg.sender === 'USER' 
                ? 'bg-term-amber/10 border border-term-amber/30 text-term-amber rounded-tl-lg rounded-bl-lg rounded-br-lg' 
                : 'bg-transparent text-stone-300 border-l-2 border-stone-700 pl-4'}
            `}>
              {msg.sender === 'AI' ? renderMessageContent(msg.text) : (
                <span className="text-term-amber font-bold">> {msg.text}</span>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-center gap-2 text-term-amber/50 font-mono text-xs ml-4">
            <div className="w-2 h-2 bg-current animate-bounce"></div>
            <div className="w-2 h-2 bg-current animate-bounce delay-75"></div>
            <div className="w-2 h-2 bg-current animate-bounce delay-150"></div>
            <span>PROCESSING INPUT...</span>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="flex-none p-4 bg-black border-t border-stone-800 z-20">
        <div className="relative flex items-center border border-stone-700 bg-stone-900/50 focus-within:border-term-amber focus-within:ring-1 focus-within:ring-term-amber/20 transition-all">
          <span className="pl-3 text-term-amber font-mono font-bold">{'>'}</span>
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Enter command or action..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-white font-mono text-sm p-3 resize-none h-12 md:h-14 placeholder-stone-600"
            disabled={isLoading}
          />
          <button 
            onClick={handleSend}
            disabled={isLoading || !input.trim()}
            className="px-4 py-2 mr-1 text-xs font-bold bg-term-amber text-black hover:bg-white disabled:opacity-50 disabled:cursor-not-allowed transition-colors uppercase tracking-wider"
          >
            SEND
          </button>
        </div>
        <div className="text-[9px] text-stone-600 mt-1 font-mono text-center md:text-right">
          WARSAW_NET_UPLINK_V2.0 // LATENCY: 24MS
        </div>
      </div>
    </div>
  );
};

