                  {/* MAIN CONTENT AREA - Strictly positioned above Dock */}
                  <main className="flex-1 relative bg-[radial-gradient(circle_at_center,rgba(15,15,15,1)_0%,rgba(0,0,0,1)_100%)] w-full">
