                  {/* Dock Overlay - Always visible on bottom */}
                  {gameState === 'GAME' && (
                    <Dock 
                      currentTab={currentTab} 
                      onTabChange={setCurrentTab} 
                      reputationUnlocked={reputationUnlocked}
                    />
                  )}
                </>
              )}
           </div>
        </div>
      </div>
    </div>
  );
};

