  const getPercentage = () => Math.min(100, (currentWeightKg / maxWeightKg) * 100);

  // When filtering, the index passed to click handler matches filtered array, 
  // so we need to track the item properly.
  const selectedItem = selectedItemIndex !== null ? filteredItems[selectedItemIndex] : null;
  const isEquipped = selectedItem && equippedItems.includes(selectedItem.name);

