    <div className="flex justify-between text-[10px] font-bold uppercase mb-1 opacity-70 tracking-wider">
      <span>{label}</span>
      <span className="text-white font-mono">{Math.round((val/max)*100)}%</span>
    </div>
    <div className="h-3 w-full bg-black border border-white/20 p-[1px]">
       <div style={{ width: `${(val/max)*100}%` }} className={`h-full ${color} shadow-[0_0_10px_currentColor] opacity-90 transition-all duration-700 ease-out`}></div>
    </div>
  </div>
);

import React, { useState } from 'react';
import { getItem } from '../../data/items';

interface Props {
  inventory: string[];
  onCraft: (items: string[]) => void;
}

export const FabricationView: React.FC<Props> = ({ inventory, onCraft }) => {
  const [selectedItems, setSelectedItems] = useState<string[]>([]);

  // De-duplicate inventory names for display, but track count
  const uniqueItems = Array.from(new Set(inventory)).map((name) => {
    const itemName = name as string;
    return {
      name: itemName,
      count: inventory.filter(i => i === itemName).length,
      data: getItem(itemName)
    };
  });

  const toggleSelection = (name: string) => {
    if (selectedItems.includes(name)) {
      setSelectedItems(prev => prev.filter(i => i !== name));
    } else {
      if (selectedItems.length < 3) { // Limit to 3 items for combination
        setSelectedItems(prev => [...prev, name]);
      }
    }
  };

  return (
    <div className="h-full flex flex-col p-1 overflow-hidden">
      <div className="flex-none mb-4 px-2 border-b border-term-amber/30 pb-2">
         <h2 className="text-xl font-display text-white">FABRICATION_BENCH</h2>
         <p className="text-[10px] text-stone-500 font-mono">
           EXPERIMENTAL PROTOCOL: COMBINE ITEMS TO DISCOVER NEW SCHEMATICS. RESULTS NOT GUARANTEED.
         </p>
      </div>

      <div className="flex-1 flex flex-col md:flex-row gap-4 overflow-hidden px-2">

         {/* Left: Inventory List */}
         <div className="flex-1 overflow-y-auto scrollbar-thin scrollbar-thumb-stone-700 scrollbar-track-black border border-stone-800 bg-black/50 p-2">
            <div className="text-xs text-stone-500 mb-2 uppercase tracking-wider sticky top-0 bg-black z-10 pb-1 border-b border-stone-800">
              Available Resources
            </div>
            <div className="grid grid-cols-1 gap-2">
               {uniqueItems.map((item, idx) => (
                 <button 
                   key={idx}
                   onClick={() => toggleSelection(item.name)}
                   className={`
                     flex justify-between items-center p-2 border transition-all text-left
                     ${selectedItems.includes(item.name) 
                       ? 'border-term-amber bg-term-amber/20 text-white' 
                       : 'border-stone-800 text-stone-400 hover:border-stone-600'}
                   `}
                 >
                    <span className="font-mono text-xs truncate pr-2">{item.name}</span>
                    <span className="text-[10px] bg-stone-900 px-1 text-stone-500">x{item.count}</span>
                 </button>
               ))}
            </div>
         </div>

         {/* Right: Workbench */}
         <div className="flex-1 flex flex-col border border-stone-800 bg-stone-900/20 p-4 relative">
            <div className="absolute inset-0 flex items-center justify-center opacity-10 pointer-events-none">
               <div className="w-32 h-32 border-2 border-dashed border-term-amber rounded-full animate-[spin_10s_linear_infinite]"></div>
            </div>

            <div className="text-xs text-center text-term-amber mb-4 font-bold">WORKBENCH_SLOTS</div>

            <div className="flex-1 flex flex-col gap-4 justify-center items-center">
               {[0, 1, 2].map(i => (
                 <div key={i} className="w-full max-w-[200px] h-12 border border-dashed border-stone-600 flex items-center justify-center bg-black/80">
                    {selectedItems[i] ? (
                      <span className="text-white font-mono text-sm">{selectedItems[i]}</span>
                    ) : (
                      <span className="text-stone-700 text-xs">EMPTY_SLOT</span>
                    )}
                 </div>
               ))}

               {selectedItems.length >= 2 && (
                 <div className="w-0.5 h-8 bg-term-amber/50 my-2"></div>
               )}
            </div>

            <div className="mt-auto">
               <button
                 disabled={selectedItems.length < 2}
                 onClick={() => {
                   onCraft(selectedItems);
                   setSelectedItems([]);
                 }}
                 className={`
                   w-full py-4 font-display text-xl tracking-widest transition-all clip-corner
                   ${selectedItems.length >= 2 
                     ? 'bg-term-amber text-black hover:bg-white shadow-[0_0_15px_rgba(255,176,0,0.3)]' 
                     : 'bg-stone-800 text-stone-600 cursor-not-allowed'}
                 `}
               >
                 {selectedItems.length < 2 ? 'SELECT_COMPONENTS' : 'INITIATE_COMBINATION'}
               </button>
            </div>
         </div>
      </div>
    </div>
  );
};

